  const money = n => (Number(n)||0).toLocaleString('pt-BR',{style:'currency',currency:'BRL'});
  function parseDateBR(value){
    const raw = String(value || '').trim();
    if(!raw) return null;
    if(/^\d{4}-\d{2}-\d{2}$/.test(raw)) return new Date(raw + 'T00:00:00');
    const m = raw.match(/^(\d{1,2})[\/.-](\d{1,2})[\/.-](\d{2,4})$/);
    if(m){
      const y = m[3].length === 2 ? '20' + m[3] : m[3];
      return new Date(`${y}-${m[2].padStart(2,'0')}-${m[1].padStart(2,'0')}T00:00:00`);
    }
    const d = new Date(raw);
    return Number.isNaN(d.getTime()) ? null : d;
  }
  const daysLate = date => {
    const venc = parseDateBR(date);
    if(!venc) return 0;
    const hoje = new Date();
    hoje.setHours(0,0,0,0);
    venc.setHours(0,0,0,0);
    // Regra da Via do Terno: conta como inadimplência somente 1 dia após o vencimento.
    // Ex.: vence em 25/06; em 26/06 passa a contar 1 dia de atraso.
    return Math.max(0, Math.floor((hoje - venc)/86400000));
  };
  const diasRegistroAtual = r => {
    const venc = parseDateBR(r?.vencimento);
    if(venc) return daysLate(r.vencimento);
    const d = Number(r?.dias);
    return Number.isFinite(d) ? d : 0;
  };
