  function acaoTempoMs(a){
    if(!a) return 0;
    if(Number.isFinite(Number(a.criadoEmMs))) return Number(a.criadoEmMs);
    if(a.criadoEm){
      const t = new Date(a.criadoEm).getTime();
      if(Number.isFinite(t)) return t;
    }
    if(a.data){
      const t = new Date(String(a.data) + 'T' + (a.hora || '00:00')).getTime();
      if(Number.isFinite(t)) return t;
    }
    return 0;
  }

  function safeId(valor){
    return String(valor ?? '')
      .normalize('NFD').replace(/[\u0300-\u036f]/g,'')
      .replace(/[^a-zA-Z0-9_-]+/g,'_')
      .replace(/^_+|_+$/g,'')
      .slice(0,180) || ('id_' + Date.now().toString(36));
  }

  function limparUndefined(obj){
    Object.keys(obj).forEach(k=>{
      if(obj[k] === undefined) delete obj[k];
      else if(obj[k] && typeof obj[k] === 'object' && !Array.isArray(obj[k])) limparUndefined(obj[k]);
      else if(Array.isArray(obj[k])) obj[k] = obj[k].map(item=>{
        if(item && typeof item === 'object') limparUndefined(item);
        return item;
      });
    });
    return obj;
  }


  function listaDuplicatasTicket(a){
    const raw = Array.isArray(a?.duplicatasSelecionadas) ? a.duplicatasSelecionadas : [];
    return raw.map(d => String(d?.id || d?.duplicata || d?.fatura || d?.pedido || d || '').trim())
      .filter(Boolean)
      .sort();
  }

  function chaveDuplicidadeTicket(a){
    // Chave agressiva para remover tickets realmente duplicados.
    // Ignora horários/IDs diferentes e pequenas variações de espaços/acentos.
    // Quando há duplicatas selecionadas, elas são o principal identificador do chamado.
    const dupsKey = listaDuplicatasTicket(a).join(',');
    const cliente = a?.clienteKey || a?.codcli || norm(a?.cliente);
    const estagio = statusVisualTicket(a);
    const resultado = a?.resultado || '';
    const responsavel = a?.responsavel || '';
    const valor = Number(a?.promessaValor || a?.valorPrometido || a?.totalSelecionado || 0);
    const obs = norm(a?.obs || a?.observacao || '').replace(/\s+/g,' ');
    const dataBase = String(a?.data || a?.proximaData || a?.criadoEmData || '').trim();

    // Com duplicatas selecionadas: se cliente, etapa e duplicatas são iguais, é o mesmo chamado.
    if(dupsKey){
      return [
        'COM_DUP',
        cliente,
        dupsKey,
        estagio,
        resultado,
        responsavel,
        valor ? valor.toFixed(2) : ''
      ].map(x => norm(x)).join('|');
    }

    // Sem duplicatas: usa também observação/data para não apagar contatos diferentes indevidamente.
    return [
      'SEM_DUP',
      cliente,
      estagio,
      resultado,
      responsavel,
      valor ? valor.toFixed(2) : '',
      dataBase,
      obs
    ].map(x => norm(x)).join('|');
  }

  function ehMesmoTicketFuzzy(a,b){
    const ca = a?.clienteKey || a?.codcli || norm(a?.cliente);
    const cb = b?.clienteKey || b?.codcli || norm(b?.cliente);
    if(norm(ca) !== norm(cb)) return false;
    if(norm(statusVisualTicket(a)) !== norm(statusVisualTicket(b))) return false;
    if(norm(a?.resultado||'') !== norm(b?.resultado||'')) return false;
    if(norm(a?.responsavel||'') !== norm(b?.responsavel||'')) return false;
    const da = listaDuplicatasTicket(a).join(',');
    const db = listaDuplicatasTicket(b).join(',');
    if(da && db && da === db) return true;
    const va = Number(a?.promessaValor || a?.valorPrometido || a?.totalSelecionado || 0).toFixed(2);
    const vb = Number(b?.promessaValor || b?.valorPrometido || b?.totalSelecionado || 0).toFixed(2);
    const oa = norm(a?.obs || a?.observacao || '').replace(/\s+/g,' ');
    const ob = norm(b?.obs || b?.observacao || '').replace(/\s+/g,' ');
    const ta = acaoTempoMs(a), tb = acaoTempoMs(b);
    const diff = Math.abs((ta||0) - (tb||0));
    return va === vb && oa === ob && diff <= 10 * 60 * 1000;
  }

  function deduplicarTicketsLista(listaTickets){
    if(!Array.isArray(listaTickets)) return [];
    const ordenados = [...listaTickets].sort((a,b)=>acaoTempoMs(a)-acaoTempoMs(b)); // mantém o mais antigo
    const mantidos = [];
    const vistos = new Map();

    ordenados.forEach(t => {
      const key = chaveDuplicidadeTicket(t);
      let duplicado = key && vistos.has(key);
      if(!duplicado){
        duplicado = mantidos.some(m => ehMesmoTicketFuzzy(m,t));
      }
      if(!duplicado){
        mantidos.push(t);
        if(key) vistos.set(key, t);
      }
    });

    return mantidos.sort((a,b)=>acaoTempoMs(b)-acaoTempoMs(a));
  }

  async function limparTicketsDuplicadosNuvem(listaTickets){
    if(limpezaDuplicadosTicketsEmAndamento || !cloudAtivo || !window.firebaseDB || !window.firebaseAuth?.currentUser) return;
    if(!Array.isArray(listaTickets) || listaTickets.length < 2) return;

    const ordenados = [...listaTickets].sort((a,b)=>acaoTempoMs(a)-acaoTempoMs(b));
    const mantidos = [];
    const vistos = new Map();
    const apagar = [];

    ordenados.forEach(t => {
      const key = chaveDuplicidadeTicket(t);
      let duplicado = key && vistos.has(key);
      if(!duplicado){
        duplicado = mantidos.some(m => ehMesmoTicketFuzzy(m,t));
      }
      if(duplicado){
        apagar.push(t);
      }else{
        mantidos.push(t);
        if(key) vistos.set(key, t);
      }
    });

    if(!apagar.length) return;
    limpezaDuplicadosTicketsEmAndamento = true;
    try{
      const fs = await obterFirestoreApi();
      if(!fs) return;
      const { collection, doc, deleteDoc } = fs;
      for(const item of apagar){
        const id = item._docId || item.cloudId;
        if(id) await deleteDoc(doc(collection(window.firebaseDB, 'tickets'), String(id)));
      }
      atualizarIndicadorNuvem(`${apagar.length} ticket(s) duplicado(s) removido(s) da nuvem.`);
    }catch(err){
      console.error('Erro ao remover tickets duplicados:', err);
    }finally{
      limpezaDuplicadosTicketsEmAndamento = false;
    }
  }

  function docIdAcao(a){
    // ID estável: evita criar dois documentos se o usuário clicar em salvar mais de uma vez.
    if(a && a.cloudId) return String(a.cloudId);
    const base = [a?.criadoEmMs || Date.now(), a?.clienteKey || a?.cliente || 'cliente', a?.data || '', a?.hora || '', a?.tipo || 'acao', a?.statusNegociacao || ''].join('_');
    return 'ticket_' + safeId(base).slice(0,160);
  }

  async function salvarAcaoNuvem(acao){
    const fs = await obterFirestoreApi();
    if(!fs || !window.firebaseDB || !window.firebaseAuth?.currentUser) return false;
    const { collection, doc, setDoc, serverTimestamp } = fs;
    if(!acao.cloudId) acao.cloudId = docIdAcao(acao);
    if(!acao.criadoEmMs) acao.criadoEmMs = Date.now();
    const payload = limparUndefined({
      ...acao,
      cloudId: acao.cloudId,
      atualizadoPor: usuarioAtualEmail(),
      atualizadoEm: serverTimestamp()
    });
    await setDoc(doc(collection(window.firebaseDB, 'tickets'), acao.cloudId), payload, {merge:true});
    return true;
  }

  async function assinarDadosNuvem(){
    const fs = await obterFirestoreApi();
    if(!fs || !window.firebaseDB || !window.firebaseAuth?.currentUser) return;

    if(cloudUnsubRegistros) cloudUnsubRegistros();
    if(cloudUnsubImportacoes) cloudUnsubImportacoes();
    if(cloudUnsubAcoes) cloudUnsubAcoes();
    if(cloudUnsubClientes) cloudUnsubClientes();

    const { collection, onSnapshot, query, orderBy } = fs;
    cloudAtivo = true;

    cloudUnsubRegistros = onSnapshot(
      query(collection(window.firebaseDB, 'registros'), orderBy('cliente')),
      (snap)=>{
        cloudRegistrosIds = new Set();
        const lista = [];
        snap.forEach(docSnap=>{
          const data = docSnap.data() || {};
          cloudRegistrosIds.add(docSnap.id);
          lista.push(normalizarRegistroERP(data));
        });
        registros = lista;
        cloudSincronizado = true;
        clienteSelecionadoKey = registros.length ? (clienteSelecionadoKey || clienteKey(agrupar()[0] || {})) : null;
        localStorage.setItem(LS, JSON.stringify({registros,acoes,arquivosImportados,clientesCadastro}));
        render();
        atualizarIndicadorNuvem('Dados sincronizados na nuvem.');
      },
      (err)=>{
        console.error('Erro ao sincronizar registros do Firestore:', err);
        atualizarIndicadorNuvem('Não foi possível sincronizar clientes/duplicatas na nuvem.');
      }
    );

    cloudUnsubImportacoes = onSnapshot(
      collection(window.firebaseDB, 'importacoes'),
      (snap)=>{
        arquivosImportados = [];
        snap.forEach(docSnap=>arquivosImportados.push((docSnap.data() || {}).hash || docSnap.id.replace(/^imp_/,'')));
        localStorage.setItem(LS, JSON.stringify({registros,acoes,arquivosImportados,clientesCadastro}));
      },
      (err)=>console.error('Erro ao sincronizar importações:', err)
    );


    cloudUnsubClientes = onSnapshot(
      query(collection(window.firebaseDB, 'clientes_cadastro'), orderBy('nome')),
      (snap)=>{
        const lista = [];
        snap.forEach(docSnap=>{ lista.push(normalizarClienteCadastro({...docSnap.data(), cloudId: docSnap.id})); });
        clientesCadastro = lista;
        localStorage.setItem(LS, JSON.stringify({registros,acoes,arquivosImportados,clientesCadastro}));
        renderClientesCadastro();
      },
      (err)=>console.error('Erro ao sincronizar base de clientes:', err)
    );


    cloudUnsubAcoes = onSnapshot(
      collection(window.firebaseDB, 'tickets'),
      (snap)=>{
        const mapaTickets = new Map();
        const todosTicketsSnap = [];
        snap.forEach(docSnap=>{
          const data = docSnap.data() || {};
          const item = {...data, cloudId: data.cloudId || docSnap.id, _docId: docSnap.id};
          todosTicketsSnap.push(item);
          const chave = String(item.cloudId || docSnap.id);
          // Firestore é a fonte da verdade. Mantemos apenas um item por cloudId.
          mapaTickets.set(chave, item);
        });
        acoes = deduplicarTicketsLista(Array.from(mapaTickets.values()));
        limparTicketsDuplicadosNuvem(todosTicketsSnap);
        normalizarTicketsCRM();
        localStorage.setItem(LS, JSON.stringify({registros,acoes,arquivosImportados,clientesCadastro}));
        atualizarInfoBackupTickets();
        render();
      },
      (err)=>console.error('Erro ao sincronizar tickets/CRM:', err)
    );
  }

  async function iniciarSincronizacaoNuvem(){
    const auth = await obterAuthApi();
    if(!auth || !window.firebaseAuth) return;
    auth.onAuthStateChanged(window.firebaseAuth, (user)=>{
      if(user){
        assinarDadosNuvem();
      } else {
        cloudAtivo = false;
        cloudSincronizado = false;
        if(cloudUnsubRegistros){ cloudUnsubRegistros(); cloudUnsubRegistros = null; }
        if(cloudUnsubImportacoes){ cloudUnsubImportacoes(); cloudUnsubImportacoes = null; }
        if(cloudUnsubAcoes){ cloudUnsubAcoes(); cloudUnsubAcoes = null; }
        if(cloudUnsubClientes){ cloudUnsubClientes(); cloudUnsubClientes = null; }
      }
    });
  }

  async function salvarRegistrosNaNuvem(novos, assinaturaArquivo, fileName){
    const fs = await obterFirestoreApi();
    if(!fs || !window.firebaseDB || !window.firebaseAuth?.currentUser) return {ok:false, salvos:0};

    const { collection, doc, writeBatch, serverTimestamp, setDoc } = fs;
    let salvos = 0;
    const usuario = usuarioAtualEmail();

    for(let i=0; i<novos.length; i+=450){
      const lote = novos.slice(i, i+450);
      const batch = writeBatch(window.firebaseDB);

      lote.forEach(reg=>{
        const idDoc = docIdRegistro(reg);
        if(cloudRegistrosIds.has(idDoc)) return;
        cloudRegistrosIds.add(idDoc);
        salvos++;
        const payload = {
          ...reg,
          dias: diasRegistroAtual(reg),
          idUnico: idRegistro(reg),
          importadoPor: usuario,
          importadoEm: serverTimestamp(),
          arquivoHash: assinaturaArquivo || '',
          arquivoNome: fileName || ''
        };
        Object.keys(payload).forEach(k=>{ if(payload[k] === undefined) delete payload[k]; });
        batch.set(doc(collection(window.firebaseDB, 'registros'), idDoc), payload, {merge:false});
      });

      if(lote.length) await batch.commit();
    }

    if(assinaturaArquivo && salvos > 0){
      await setDoc(doc(collection(window.firebaseDB, 'importacoes'), docIdImportacao(assinaturaArquivo)), {
        hash: assinaturaArquivo,
        nome: fileName || '',
        linhasNovas: salvos,
        usuario,
        criadoEm: serverTimestamp()
      }, {merge:true});
    }

    return {ok:true, salvos};
  }

  async function limparDadosNuvem(){
    const fs = await obterFirestoreApi();
    if(!fs || !window.firebaseDB || !window.firebaseAuth?.currentUser) return false;
    const { collection, getDocs, writeBatch } = fs;

    async function apagarColecao(nome){
      const snap = await getDocs(collection(window.firebaseDB, nome));
      const docs = snap.docs || [];
      for(let i=0; i<docs.length; i+=450){
        const batch = writeBatch(window.firebaseDB);
        docs.slice(i, i+450).forEach(d=>batch.delete(d.ref));
        await batch.commit();
      }
    }

    await apagarColecao('registros');
    await apagarColecao('importacoes');
    return true;
  }

  const compareValues = (a,b,campo) => {
    const numeric = ['total','maiorAtraso','valor','dias'].includes(campo);
    const date = ['emissao','vencimento'].includes(campo);
    if(date){ return (parseDateBR(a[campo])?.getTime()||0) - (parseDateBR(b[campo])?.getTime()||0); }
    if(numeric) return (Number(a[campo])||0) - (Number(b[campo])||0);
    return String(a[campo]||'').localeCompare(String(b[campo]||''),'pt-BR',{numeric:true,sensitivity:'base'});
  };
  function ordenarLista(lista, sort){
    return [...lista].sort((a,b)=>{
      const r = compareValues(a,b,sort.campo);
      return sort.dir === 'asc' ? r : -r;
    });
  }
  function marcarOrdenacao(){
    document.querySelectorAll('[data-sort-clientes]').forEach(th=>{
      const c = th.dataset.sortClientes;
      th.classList.toggle('active-sort', c === sortClientes.campo);
      th.dataset.dir = c === sortClientes.campo ? (sortClientes.dir === 'asc' ? '▲' : '▼') : '';
    });
    document.querySelectorAll('[data-sort-historico]').forEach(th=>{
      const c = th.dataset.sortHistorico;
      th.classList.toggle('active-sort', c === sortHistorico.campo);
      th.dataset.dir = c === sortHistorico.campo ? (sortHistorico.dir === 'asc' ? '▲' : '▼') : '';
    });
    document.querySelectorAll('[data-sort-clientes-cadastro]').forEach(th=>{
      const c = th.dataset.sortClientesCadastro;
      th.classList.toggle('active-sort', c === sortClientesCadastro.campo);
      th.dataset.dir = c === sortClientesCadastro.campo ? (sortClientesCadastro.dir === 'asc' ? '▲' : '▼') : '';
    });
  }

  function scoreCliente(c){
    // Regra comercial atual:
    // até 9 dias vencidos = Excelente | 10 dias = Atenção | acima de 10 dias = Não vender
    const maxDias = Math.max(...c.duplicatas.map(d=>Number(d.dias)||0),0);
    if(maxDias > 10) return 'Não vender';
    if(maxDias === 10) return 'Atenção';
    return 'Excelente';
  }
  function scoreClass(s){ return s==='Excelente'?'s-excelente':s==='Atenção'?'s-atencao':'s-nao'; }
  function scoreIcon(s){ return s==='Excelente'?'🟢':s==='Atenção'?'🟡':'🔴'; }

  function agrupar(){
    const mapa = new Map();
    registrosInadimplentes().forEach(r=>{
      const key = r.codcli || r.cliente;
      if(!mapa.has(key)) mapa.set(key,{codcli:r.codcli,cliente:r.cliente,fantasia:r.fantasia,representante:r.representante,cidade:r.cidade,telefone:r.telefone,total:0,duplicatas:[]});
      const c = mapa.get(key);
      const dias = diasRegistroAtual(r);
      c.total += Number(r.valor) || 0;
      c.duplicatas.push({...r,dias});
    });
    return Array.from(mapa.values()).map(c=>({...c,score:scoreCliente(c),maiorAtraso:Math.max(...c.duplicatas.map(d=>d.dias),0)}));
  }


