  function ticketEstaPago(a){
    const txt = norm([a && a.statusNegociacao, a && a.estagio, a && a.tipo, a && a.resultado, a && a.statusPromessa].filter(Boolean).join(' '));
    return txt.includes('pago') || txt.includes('pagamento realizado') || txt.includes('cumprida');
  }

  function clientePossuiPago(c){
    const key = clienteKey(c);
    const relacionadas = acoes.filter(a => !a.excluido && ((a.clienteKey && a.clienteKey === key) || (a.codcli && String(a.codcli) === String(c.codcli||'')) || norm(a.cliente) === norm(c.cliente)));
    if(!relacionadas.length) return false;
    // Considera quitado apenas quando a ação mais recente do cliente for Pago/Pagamento realizado.
    // Assim clientes com pagamento antigo, mas ainda importados com títulos vencidos, continuam aparecendo na fila automática.
    const ordenadas = relacionadas.slice().sort((a,b)=>{
      const da = new Date(a.criadoEm || a.dataAcao || a.atualizadoEm || a.dataPromessa || 0).getTime() || 0;
      const db = new Date(b.criadoEm || b.dataAcao || b.atualizadoEm || b.dataPromessa || 0).getTime() || 0;
      return db - da;
    });
    return ticketEstaPago(ordenadas[0]);
  }

  function ticketsAbertosCliente(c){
    const key = clienteKey(c);
    return acoes.filter(a => !a.excluido && ((a.clienteKey && a.clienteKey === key) || (a.codcli && String(a.codcli) === String(c.codcli||'')) || norm(a.cliente) === norm(c.cliente)) && !ticketEstaPago(a));
  }

  function faixaAgendaAutomaticaPorDias(dias){
    dias = Number(dias)||0;
    if(dias >= 1 && dias <= 29) return '129';
    if(dias >= 30 && dias <= 45) return '3045';
    if(dias >= 46 && dias <= 59) return '4659';
    if(dias >= 60) return '60';
    return '';
  }

  function faixaAgendaAutomatica(c){
    // Mantido para compatibilidade com outras rotinas.
    return faixaAgendaAutomaticaPorDias(Number(c?.maiorAtraso)||0);
  }

  function valorDuplicatas(lista){
    return (lista || []).reduce((s,d)=>s+(Number(d.valor)||0),0);
  }

  function renderAgendaAutomatica(){
    if(!$('agenda-automatica')) return;
    const grupos = { '129': [], '3045': [], '4659': [], '60': [] };
    // A fila automática deve ser baseada nas duplicatas vencidas importadas.
    // Não removemos mais o cliente da fila por causa de uma ação/ticket pago,
    // porque ele pode ter pago uma duplicata antiga e ainda possuir outras vencidas.
    // Se a duplicata continua no CSV/importação e tem 1+ dia de atraso, ela deve aparecer.
    const clientes = agrupar().filter(c =>
      (c.duplicatas || []).some(d => (Number(diasRegistroAtual(d)) || Number(d.dias) || 0) >= 1)
    );

    // Um mesmo cliente pode ter duplicatas em faixas diferentes.
    // Ex.: uma duplicata com 124 dias e outras com 2 dias. Antes ele aparecia só em 60+;
    // agora aparece também em 1 a 29, usando as duplicatas daquela faixa.
    clientes.forEach(c=>{
      const dupsPorFaixa = { '129': [], '3045': [], '4659': [], '60': [] };
      (c.duplicatas || []).forEach(d=>{
        const diasDup = Number(diasRegistroAtual(d)) || Number(d.dias) || 0;
        const faixa = faixaAgendaAutomaticaPorDias(diasDup);
        if(faixa) dupsPorFaixa[faixa].push({...d, dias: diasDup});
      });

      const abertos = ticketsAbertosCliente(c);
      Object.entries(dupsPorFaixa).forEach(([faixa, dups])=>{
        if(!dups.length) return;
        const maiorFaixa = Math.max(...dups.map(d=>Number(d.dias)||0),0);
        const menorFaixa = Math.min(...dups.map(d=>Number(d.dias)||0).filter(n=>n>0), maiorFaixa || 0);
        grupos[faixa].push({
          ...c,
          duplicatasFaixa: dups,
          totalFaixa: valorDuplicatas(dups),
          maiorAtrasoFaixa: maiorFaixa,
          menorAtrasoFaixa: menorFaixa,
          ticketsAbertos: abertos,
          temTicketAberto: abertos.length > 0
        });
      });
    });
    Object.keys(grupos).forEach(k=>{
      grupos[k].sort((a,b)=>{
        if(a.temTicketAberto !== b.temTicketAberto) return a.temTicketAberto ? 1 : -1;
        const da = Number(a.menorAtrasoFaixa || a.maiorAtrasoFaixa || a.maiorAtraso)||0;
        const db = Number(b.menorAtrasoFaixa || b.maiorAtrasoFaixa || b.maiorAtraso)||0;
        if(da !== db) return da-db;
        return (Number(b.totalFaixa || b.total)||0)-(Number(a.totalFaixa || a.total)||0);
      });
    });
    const ids = { '129':'autoAgenda129', '3045':'autoAgenda3045', '4659':'autoAgenda4659', '60':'autoAgenda60' };
    const counts = { '129':'autoCount129', '3045':'autoCount3045', '4659':'autoCount4659', '60':'autoCount60' };
    const buscaIds = { '129':'autoBusca129', '3045':'autoBusca3045', '4659':'autoBusca4659', '60':'autoBusca60' };
    Object.entries(grupos).forEach(([k,listaOriginal])=>{
      const box = $(ids[k]); if(!box) return;
      const termoBusca = norm($(buscaIds[k])?.value || '');
      const lista = termoBusca ? listaOriginal.filter(c=>{
        const texto = norm([c.cliente, c.codcli, c.cidade, c.representante, telefoneCompleto(c)].filter(Boolean).join(' '));
        return texto.includes(termoBusca);
      }) : listaOriginal;
      if($(counts[k])) $(counts[k]).textContent = termoBusca ? `${lista.length}/${listaOriginal.length}` : listaOriginal.length;
      box.innerHTML = lista.length ? lista.map(c=>{
        const key = clienteKey(c);
        const abertosTxt = c.ticketsAbertos && c.ticketsAbertos.length ? c.ticketsAbertos.map(ticketLabel).join(', ') : '';
        const dups = Number(c.duplicatasFaixa?.length || c.duplicatas?.length)||0;
        const atrasoMin = Number(c.menorAtrasoFaixa || c.maiorAtrasoFaixa || c.maiorAtraso)||0;
        const atrasoMax = Number(c.maiorAtrasoFaixa || c.maiorAtraso)||0;
        const atrasoLabel = atrasoMin && atrasoMax && atrasoMin !== atrasoMax ? `${atrasoMin}-${atrasoMax} dias` : `${atrasoMax || atrasoMin} dias`;
        const valorFila = Number(c.totalFaixa || c.total)||0;
        return `<article class="auto-agenda-card ${c.temTicketAberto ? 'com-ticket' : ''}">
          <div class="auto-agenda-card-top"><strong>${htm(c.cliente || '-')}</strong><span>${htm(atrasoLabel)}</span></div>
          <small>${htm(c.codcli || '')}${c.representante ? ' • Rep. ' + htm(c.representante) : ''}${c.cidade ? ' • ' + htm(c.cidade) : ''}</small>
          <div class="auto-agenda-metrics"><b>${money(valorFila)}</b><span>${dups} duplicata(s) na faixa</span></div>
          ${c.totalFaixa && c.totalFaixa !== c.total ? `<small class="auto-total-cliente">Total do cliente: ${money(c.total||0)} • Maior atraso geral: ${Number(c.maiorAtraso)||0} dias</small>` : ''}
          ${c.temTicketAberto ? `<div class="auto-ticket-alert">Já possui ticket aberto: ${htm(abertosTxt)}. Cliente movido para o final da fila.</div>` : `<div class="auto-ticket-ok">Sem ticket aberto. Priorizar contato.</div>`}
          <div class="auto-agenda-actions"><button type="button" class="secondary" data-auto-historico="${htm(key)}">Ver histórico</button><button type="button" class="secondary" data-auto-iniciar="${htm(key)}">${c.temTicketAberto ? 'Continuar chamado' : 'Iniciar chamado'}</button></div>
        </article>`;
      }).join('') : '<div class="auto-agenda-empty">Nenhum cliente nessa faixa.</div>';
    });
    const total = Object.values(grupos).reduce((s,l)=>s+l.length,0);
    const comTicket = Object.values(grupos).flat().filter(c=>c.temTicketAberto).length;
    if($('agendaAutoResumo')) $('agendaAutoResumo').innerHTML = `<div><small>Total na fila</small><strong>${total}</strong></div><div><small>Prioridade 1 a 29</small><strong>${grupos['129'].length}</strong></div><div><small>46 a 59 dias</small><strong>${grupos['4659'].length}</strong></div><div><small>Com ticket aberto</small><strong>${comTicket}</strong></div><div><small>Sem ticket aberto</small><strong>${total-comTicket}</strong></div>`;
  }


  function render(){
    const clientes = agrupar();
    const total = clientes.reduce((s,c)=>s+c.total,0);
    const qtdDup = clientes.reduce((s,c)=>s + (c.duplicatas?.length || 0), 0);
    const risco = clientes.filter(c=>c.score==='Não vender').length;
    const acima30 = clientes.filter(c=>c.maiorAtraso>=30).reduce((s,c)=>s+c.total,0);
    if($('mTotalVencido')) $('mTotalVencido').textContent = money(total);
    if($('mQtdDuplicatas')) $('mQtdDuplicatas').textContent = `${qtdDup} duplicatas em aberto`;
    if($('mClientesRisco')) $('mClientesRisco').textContent = risco;
    if($('mAcima30')) $('mAcima30').textContent = money(acima30);

    const faixas = [
      {label:'0-30 dias', min:0, max:30},
      {label:'31-60 dias', min:31, max:60},
      {label:'61-90 dias', min:61, max:90},
      {label:'90+ dias', min:91, max:Infinity}
    ].map(f=>{
      const valor = clientes.filter(c=>c.maiorAtraso>=f.min && c.maiorAtraso<=f.max).reduce((s,c)=>s+c.total,0);
      return {...f, valor};
    });
    const maiorFaixa = Math.max(...faixas.map(f=>f.valor),1);
    if($('faixasAtraso')) $('faixasAtraso').innerHTML = faixas.map(f=>`<div class="summary-row"><strong>${f.label}</strong><div class="mini-bar"><span style="width:${Math.max(4,(f.valor/maiorFaixa)*100)}%"></span></div><strong>${money(f.valor)}</strong></div>`).join('');

    const scoreCounts = {'Excelente':0,'Atenção':0,'Não vender':0};
    clientes.forEach(c=>scoreCounts[c.score]=(scoreCounts[c.score]||0)+1);
    if($('scoresResumo')) $('scoresResumo').innerHTML = Object.entries(scoreCounts).map(([score,qtd])=>`<div class="score-box ${scoreClass(score)}">${scoreIcon(score)} ${score}<small>${qtd} cliente(s)</small></div>`).join('');

    const ranking = [...clientes].sort((a,b)=>{
      const dias = (b.maiorAtraso||0) - (a.maiorAtraso||0);
      if(dias !== 0) return dias;
      return (b.total||0) - (a.total||0);
    });
    if($('rankingBody')) $('rankingBody').innerHTML = ranking.map((c,i)=>`<tr><td>${i+1}º</td><td class="client-name"><strong>${c.cliente}</strong><small>${c.codcli||''} ${c.representante?`• ${c.representante}`:''}</small></td><td><strong>${c.maiorAtraso} dias</strong></td><td>${money(c.total)}</td><td><span class="score ${scoreClass(c.score)}">${scoreIcon(c.score)} ${c.score}</span></td></tr>`).join('') || '<tr><td colspan="5">Sem dados.</td></tr>';

    const reps = {};
    clientes.forEach(c=>{
      const rep = c.representante || 'Sem representante';
      if(!reps[rep]) reps[rep] = {valor:0, clientes:0, maiorAtraso:0};
      reps[rep].valor += c.total || 0;
      reps[rep].clientes += 1;
      reps[rep].maiorAtraso = Math.max(reps[rep].maiorAtraso, c.maiorAtraso || 0);
    });
    const max = Math.max(...Object.values(reps).map(r=>r.valor),1);
    if($('representantesBody')) $('representantesBody').innerHTML = Object.entries(reps).sort((a,b)=>b[1].valor-a[1].valor).map(([rep,dados],i)=>`<div class="rep-item"><strong><span>${i+1}º ${rep}</span><span>${money(dados.valor)}</span></strong><small>${dados.clientes} cliente(s) • maior atraso: ${dados.maiorAtraso} dias</small><div class="bar"><span style="width:${Math.max(8,(dados.valor/max)*100)}%"></span></div></div>`).join('') || '<p>Sem dados.</p>';

    renderClientes();
    renderHistorico();
    renderCrm();
    renderAgendaAutomatica();
    renderHistoricoPorCliente();
    renderClientesCadastro();
    localStorage.setItem(LS, JSON.stringify({registros,acoes,arquivosImportados,clientesCadastro}));
    try { if(typeof atualizarPreviewRelatorio === 'function') atualizarPreviewRelatorio(); } catch(e) { console.error('Erro na prévia de relatórios:', e); }
  }

  function renderClientes(){
    const busca = norm($('busca').value);
    const fs = $('filtroScore').value;
    let clientes = agrupar().filter(c=>{
      const txt = norm([c.cliente,c.codcli,c.cidade,c.representante,c.fantasia].join(' '));
      return (!busca || txt.includes(busca)) && (!fs || c.score===fs);
    });
    clientes = ordenarLista(clientes, sortClientes);
    if(!clienteSelecionadoKey && clientes.length) clienteSelecionadoKey = clienteKey(clientes[0]);
    $('clientesBody').innerHTML = clientes.map(c=>{
      const key = clienteKey(c);
      return `<tr class="${key===clienteSelecionadoKey?'selected-row':''}" data-row-key="${key}">
        <td class="client-name sticky-col"><strong>${c.cliente}</strong><small>${c.fantasia||''} ${telefoneCompleto(c)?`• ${telefoneCompleto(c)}`:''}</small></td>
        <td>${c.codcli||'-'}</td><td>${c.representante||'-'}</td><td>${c.cidade||'-'}</td>
        <td><strong>${money(c.total)}</strong></td><td>${c.maiorAtraso} dias</td>
        <td><span class="score ${scoreClass(c.score)}">${scoreIcon(c.score)} ${c.score}</span></td>
        <td><button class="secondary" data-select="${key}">Ver histórico</button></td>
      </tr>`;
    }).join('') || '<tr><td colspan="8">Nenhum cliente encontrado.</td></tr>';
    marcarOrdenacao();
  }

  function renderHistorico(){
    if(!$('historicoTitulo') || !$('historicoSubtitulo') || !$('historicoResumo') || !$('historicoBody')) return;
    const clientes = agrupar();
    const c = clientes.find(x=>clienteKey(x)===clienteSelecionadoKey) || clientes[0];
    if(!c){
      $('historicoTitulo').textContent = 'Histórico do cliente';
      $('historicoSubtitulo').textContent = 'Importe dados ou carregue a demonstração.';
      $('historicoResumo').innerHTML = '';
      $('historicoBody').innerHTML = '<tr><td colspan="7">Sem dados.</td></tr>';
      marcarOrdenacao();
      return;
    }
    clienteSelecionadoKey = clienteKey(c);
    $('historicoTitulo').textContent = c.cliente;
    $('historicoSubtitulo').textContent = `${c.codcli||'-'} • ${c.representante||'Sem representante'} • ${c.cidade||'-'} • ${telefoneCompleto(c)||'sem telefone'}`;
    $('historicoResumo').innerHTML = `
      <div><small>Total vencido</small><strong>${money(c.total)}</strong></div>
      <div><small>Maior atraso</small><strong>${c.maiorAtraso} dias</strong></div>
      <div><small>Duplicatas</small><strong>${c.duplicatas.length}</strong></div>
      <div><small>Score</small><strong><span class="score ${scoreClass(c.score)}">${scoreIcon(c.score)} ${c.score}</span></strong></div>`;
    const historico = ordenarLista(c.duplicatas, sortHistorico);
    $('historicoBody').innerHTML = historico.map(d=>`<tr>
      <td>${d.duplicata||'-'}</td><td>${d.fatura||'-'}</td><td>${d.pedido||'-'}</td><td>${d.emissao||'-'}</td><td>${d.vencimento||'-'}</td>
      <td><strong>${money(d.valor)}</strong></td><td>${Number.isFinite(Number(d.dias)) ? Number(d.dias) : 0} dias</td><td>${d.status||'-'}</td>
    </tr>`).join('') || '<tr><td colspan="7">Sem duplicatas.</td></tr>';
    marcarOrdenacao();
  }

  function crmDateObj(valor){
    if(!valor) return null;
    if(valor instanceof Date) return valor;
    const s = String(valor).trim();
    if(/^\d{4}-\d{2}-\d{2}$/.test(s)) return new Date(s+'T00:00:00');
    const m = s.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
    if(m) return new Date(`${m[3]}-${m[2]}-${m[1]}T00:00:00`);
    if(s === 'Hoje') return new Date(new Date().toDateString());
    if(s === 'Amanhã') { const d = new Date(new Date().toDateString()); d.setDate(d.getDate()+1); return d; }
    return null;
  }
  function crmDataBR(valor){
    const d = crmDateObj(valor);
    if(!d || isNaN(d.getTime())) return valor || '-';
    return d.toLocaleDateString('pt-BR');
  }

  function crmDataHoraRegistro(a){
    let d = null;
    const origem = a?.criadoEm || a?.registroEm || a?.createdAt;
    if(origem && typeof origem === 'object'){
      if(typeof origem.toDate === 'function'){ try{ d = origem.toDate(); }catch(e){} }
      else if(Number.isFinite(Number(origem.seconds))){ d = new Date(Number(origem.seconds) * 1000); }
    }
    if(!d && origem){
      const t = new Date(origem);
      if(!Number.isNaN(t.getTime())) d = t;
    }
    if(!d && Number.isFinite(Number(a?.criadoEmMs))){
      const t = new Date(Number(a.criadoEmMs));
      if(!Number.isNaN(t.getTime())) d = t;
    }
    if(!d && (a?.criadoEmData || a?.registroData)){
      const data = a.criadoEmData || a.registroData;
      const hora = a.criadoEmHora || a.registroHora || '00:00';
      const t = crmDateObj(data);
      if(t && !Number.isNaN(t.getTime())){
        const m = String(hora).match(/^(\d{1,2}):(\d{2})/);
        if(m){ t.setHours(Number(m[1]), Number(m[2]), 0, 0); }
        d = t;
      }
    }
    if(!d){
      const t = crmDateObj(a?.data);
      if(t && !Number.isNaN(t.getTime())){
        const m = String(a?.hora || '00:00').match(/^(\d{1,2}):(\d{2})/);
        if(m){ t.setHours(Number(m[1]), Number(m[2]), 0, 0); }
        d = t;
      }
    }
    if(!d || Number.isNaN(d.getTime())) return { data: crmDataBR(a?.data), hora: htm(a?.hora || '') };
    return { data: d.toLocaleDateString('pt-BR'), hora: d.toLocaleTimeString('pt-BR', {hour:'2-digit', minute:'2-digit'}) };
  }

  function carimboAgoraLocal(){
    const d = new Date();
    return {
      iso: d.toISOString(),
      ms: d.getTime(),
      data: d.toISOString().slice(0,10),
      hora: d.toTimeString().slice(0,5)
    };
  }

  function crmRegistroDateObj(a){
    let d = null;
    const origem = a?.criadoEm || a?.registroEm || a?.createdAt;
    if(origem && typeof origem === 'object'){
      if(typeof origem.toDate === 'function'){ try{ d = origem.toDate(); }catch(e){} }
      else if(Number.isFinite(Number(origem.seconds))){ d = new Date(Number(origem.seconds) * 1000); }
    }
    if(!d && origem){
      const t = new Date(origem);
      if(!Number.isNaN(t.getTime())) d = t;
    }
    if(!d && Number.isFinite(Number(a?.criadoEmMs || a?.registroEmMs || a?.updatedAtMs))){
      const t = new Date(Number(a.criadoEmMs || a.registroEmMs || a.updatedAtMs));
      if(!Number.isNaN(t.getTime())) d = t;
    }
    if(!d && (a?.criadoEmData || a?.registroData)){
      const base = crmDateObj(a.criadoEmData || a.registroData);
      if(base){
        const m = String(a.criadoEmHora || a.registroHora || '00:00').match(/^(\d{1,2}):(\d{2})/);
        if(m) base.setHours(Number(m[1]), Number(m[2]), 0, 0);
        d = base;
      }
    }
    if(!d){
      const base = crmDateObj(a?.data);
      if(base){
        const m = String(a?.hora || '00:00').match(/^(\d{1,2}):(\d{2})/);
        if(m) base.setHours(Number(m[1]), Number(m[2]), 0, 0);
        d = base;
      }
    }
    return d && !Number.isNaN(d.getTime()) ? d : null;
  }

  function isoDateLocal(d){
    if(!d || Number.isNaN(d.getTime())) return '';
    const y=d.getFullYear();
    const m=String(d.getMonth()+1).padStart(2,'0');
    const day=String(d.getDate()).padStart(2,'0');
    return `${y}-${m}-${day}`;
  }

  function rankingCobSetPeriodoMesAtual(){
    const ini=$('rankingCobDataIni'), fim=$('rankingCobDataFim');
    if(!ini || !fim) return;
    const hoje=new Date();
    ini.value = isoDateLocal(new Date(hoje.getFullYear(), hoje.getMonth(), 1));
    fim.value = isoDateLocal(new Date(hoje.getFullYear(), hoje.getMonth()+1, 0));
  }

  function rankingCobSetPeriodoHoje(){
    const ini=$('rankingCobDataIni'), fim=$('rankingCobDataFim');
    if(!ini || !fim) return;
    const hoje=isoDateLocal(new Date());
    ini.value = hoje;
    fim.value = hoje;
  }

  function rankingCobSetPeriodoSemanaAtual(){
    const ini=$('rankingCobDataIni'), fim=$('rankingCobDataFim');
    if(!ini || !fim) return;
    const hoje=new Date();
    const dia = hoje.getDay();
    const diffSegunda = dia === 0 ? -6 : 1 - dia;
    const segunda = new Date(hoje.getFullYear(), hoje.getMonth(), hoje.getDate() + diffSegunda);
    const domingo = new Date(segunda.getFullYear(), segunda.getMonth(), segunda.getDate() + 6);
    ini.value = isoDateLocal(segunda);
    fim.value = isoDateLocal(domingo);
  }

  function rankingCobDentroPeriodo(a){
    const iniVal = $('rankingCobDataIni')?.value || '';
    const fimVal = $('rankingCobDataFim')?.value || '';
    const d = crmRegistroDateObj(a);
    if(!d) return false;
    const ini = iniVal ? new Date(iniVal+'T00:00:00') : null;
    const fim = fimVal ? new Date(fimVal+'T23:59:59') : null;
    if(ini && d < ini) return false;
    if(fim && d > fim) return false;
    return true;
  }

  function rankingCobPeriodoTexto(){
    const ini=$('rankingCobDataIni')?.value, fim=$('rankingCobDataFim')?.value;
    const f = v => v ? crmDataBR(v) : 'sem limite';
    return `Período do ranking: ${f(ini)} até ${f(fim)}`;
  }
  function crmDiasEntre(data){
    const d = crmDateObj(data);
    if(!d || isNaN(d.getTime())) return null;
    const hoje = new Date(new Date().toDateString());
    return Math.floor((d - hoje) / 86400000);
  }
  function crmClassificar(a){
    const status = String(a.statusAcao || a.statusPromessa || '').toLowerCase();
    if(status.includes('concl') || status.includes('pago') || status.includes('cumpr')) return 'concluida';
    const diff = crmDiasEntre(a.proximaData || a.dataPromessa || a.data);
    if(diff === null) return 'aberta';
    if(diff < 0) return 'atrasada';
    if(diff === 0) return 'hoje';
    return 'futura';
  }
  function crmStatusLabel(cls){
    return cls === 'atrasada' ? 'Atrasada' : cls === 'hoje' ? 'Hoje' : cls === 'concluida' ? 'Concluída' : 'Aberta';
  }
  const CRM_ESTAGIOS_FLUXO = ['Em contato','Promessa','Negociação','Protestado','Jurídico','Judicializado','Revisar pagamento','Pago'];
  const CRM_TIPOS_ACAO = ['Ligação','WhatsApp','E-mail','Visita','Retorno','Negociação','Protesto','Jurídico','Judicializado','Revisar pagamento','Pagamento realizado','Bloqueio'];
  const CRM_RESULTADOS = ['Não respondeu','Não atendeu','Prometeu pagamento','Contestou','Negociação','Protestado','Encaminhado jurídico','Judicializado','Pagamento realizado','Sem retorno'];
  const CRM_PROXIMAS_ACOES = ['Ligação','WhatsApp','E-mail','Retorno','Enviar boleto','Enviar ao protesto','Acionar jurídico','Acompanhar processo','Revisar pagamento','Bloqueio de crédito','Reunião'];

  function opcoesHtml(lista, selecionado){
    const selNorm = norm(selecionado || '');
    return lista.map(v=>`<option ${norm(v)===selNorm?'selected':''}>${v}</option>`).join('');
  }

  function responsavelPadrao(valor){
    const v = String(valor || '').trim();
    const n = norm(v);
    if(n === norm('Larissa')) return {select:'Larissa', outro:''};
    if(n === norm('Daniele')) return {select:'Daniele', outro:''};
    return {select:'Outro', outro:v && v !== 'Usuário' ? v : ''};
  }

  function responsavelSelectHtml(prefixo, valor){
    const cfg = responsavelPadrao(valor);
    return `<label class="form-field"><span>Responsável *</span><select id="${prefixo}ResponsavelSelect" required><option value="Larissa" ${cfg.select==='Larissa'?'selected':''}>Larissa</option><option value="Daniele" ${cfg.select==='Daniele'?'selected':''}>Daniele</option><option value="Outro" ${cfg.select==='Outro'?'selected':''}>Outro</option></select></label>
      <label class="form-field" id="${prefixo}ResponsavelOutroBox" style="display:${cfg.select==='Outro'?'':'none'}"><span>Nome do responsável *</span><input id="${prefixo}ResponsavelOutro" type="text" value="${htm(cfg.outro)}" placeholder="Digite o nome do responsável" /></label>`;
  }

  function configurarResponsavelSelect(prefixo){
    const select = $(`${prefixo}ResponsavelSelect`);
    const box = $(`${prefixo}ResponsavelOutroBox`);
    const input = $(`${prefixo}ResponsavelOutro`);
    function atualizar(){
      if(!select || !box) return;
      const outro = select.value === 'Outro';
      box.style.display = outro ? '' : 'none';
      if(input) input.required = outro;
    }
    if(select) select.addEventListener('change', atualizar);
    atualizar();
  }

  function obterResponsavelSelect(prefixo){
    const select = $(`${prefixo}ResponsavelSelect`);
    const input = $(`${prefixo}ResponsavelOutro`);
    if(select && select.value === 'Outro') return String((input && input.value) || '').trim();
    return String((select && select.value) || 'Usuário').trim();
  }

  function validarResponsavelSelect(prefixo, erroId){
    const select = $(`${prefixo}ResponsavelSelect`);
    const input = $(`${prefixo}ResponsavelOutro`);
    if(select && select.value === 'Outro' && !String((input && input.value) || '').trim()){
      if(erroId && $(erroId)) $(erroId).textContent = 'Informe o nome do responsável.';
      if(input) input.focus();
      return false;
    }
    return true;
  }

  function crmChecklistEtapa(a){
    const estagio = statusVisualTicket(a);
    const idx = Math.max(0, CRM_ESTAGIOS_FLUXO.indexOf(estagio));
    return {nome: estagio || 'Em contato', passo: idx + 1, total: CRM_ESTAGIOS_FLUXO.length};
  }

  function crmChecklistItens(a){
    const etapa = crmChecklistEtapa(a).nome;
    if(etapa === 'Pago') return ['Pagamento confirmado','Baixa realizada','Ticket encerrado'];
    if(etapa === 'Revisar pagamento') return ['Comprovante recebido','Comprovante conferido','Baixa financeira solicitada','Cliente informado'];
    if(etapa === 'Judicializado') return ['Processo registrado','Número do processo informado','Vara preenchida','Acompanhamento agendado'];
    if(etapa === 'Jurídico') return ['Encaminhado ao jurídico','Responsável jurídico definido','Documentos enviados','Retorno jurídico agendado'];
    if(etapa === 'Protestado') return ['Protesto solicitado','Cartório informado','Data do protesto registrada','Cliente notificado'];
    if(etapa === 'Negociação') return ['Condição negociada','Parcelamento definido','Cliente concordou','Aguardando pagamento'];
    if(etapa === 'Promessa') return ['Valor acordado','Data prometida','Cliente confirmou','Retorno agendado'];
    return ['WhatsApp enviado','Ligação realizada','Retorno agendado'];
  }

  function crmChecklistObj(a){
    if(!a.checklist || typeof a.checklist !== 'object') a.checklist = {};
    return a.checklist;
  }

  function crmChecklistCompleto(a){
    const itens = crmChecklistItens(a);
    const ck = crmChecklistObj(a);
    return itens.length > 0 && itens.every(item => !!ck[item]);
  }

  function crmChecklistProgresso(a){
    const itens = crmChecklistItens(a);
    const ck = crmChecklistObj(a);
    const feitos = itens.filter(item => !!ck[item]).length;
    return {feitos, total:itens.length, pct:itens.length ? Math.round((feitos/itens.length)*100) : 0};
  }

  function crmChecklistHtml(a, idx){
    const itens = crmChecklistItens(a);
    const ck = crmChecklistObj(a);
    const p = crmChecklistProgresso(a);
    const etapa = crmChecklistEtapa(a);
    const etapaPct = Math.round((etapa.passo / etapa.total) * 100);
    return `<div class="agenda-checklist">
      <div class="agenda-checklist-head"><span>Checklist • ${htm(etapa.nome)} <small>Etapa ${etapa.passo}/${etapa.total}</small></span><strong>${p.feitos}/${p.total}</strong></div>
      <div class="agenda-progress etapa"><span style="width:${etapaPct}%"></span></div>
      ${itens.map(item=>`<label class="agenda-check-item"><input type="checkbox" data-crm-checklist="${idx}" data-check-item="${htm(item)}" ${ck[item]?'checked':''}/> <span>${htm(item)}</span></label>`).join('')}
      <div class="agenda-progress"><span style="width:${p.pct}%"></span></div>
    </div>`;
  }

  function crmFiltrarAgenda(lista){
    const email = norm(usuarioAtualEmail());
    return lista.filter(a=>{
      const cls = crmClassificar(a);
      const status = statusVisualTicket(a);
      if(agendaFiltro === 'minhas') return norm(a.responsavel||'').includes(email) || norm(a.usuario||'').includes(email) || norm(a.criadoPor||'').includes(email) || norm(a.atualizadoPor||'').includes(email);
      if(agendaFiltro === 'atrasadas') return cls === 'atrasada';
      if(agendaFiltro === 'hoje') return cls === 'hoje';
      if(agendaFiltro === 'promessas') return status === 'Promessa';
      if(agendaFiltro === 'concluidas') return cls === 'concluida' || crmChecklistCompleto(a);
      if(agendaFiltro === 'pendentes') return cls !== 'concluida' && !crmChecklistCompleto(a);
      return true;
    });
  }

  function crmAgendaFiltrosHtml(contadores){
    const filtros = [
      ['pendentes','Pendentes',contadores.pendentes],
      ['hoje','Hoje',contadores.hoje],
      ['atrasadas','Atrasadas',contadores.atrasadas],
      ['promessas','Promessas',contadores.promessas],
      ['concluidas','Concluídas',contadores.concluidas],
      ['minhas','Minhas',contadores.minhas],
      ['todas','Todas',contadores.todas]
    ];
    return `<div class="agenda-toolbar">${filtros.map(([key,label,qtd])=>`<button type="button" class="agenda-filter ${agendaFiltro===key?'active':''}" data-agenda-filter="${key}">${label}<strong>${qtd}</strong></button>`).join('')}</div>`;
  }

  function acaoExcluida(a){
    return !!(a && (a.excluida || String(a.statusNegociacao||'').toLowerCase()==='excluída' || String(a.statusNegociacao||'').toLowerCase()==='excluida'));
  }
  function statusVisualTicket(a){
    if(acaoExcluida(a)) return 'Excluída';
    const estagio = String(a?.statusNegociacao || '').trim();
    const estagioNorm = norm(estagio);
    const tipo = norm(a?.tipo || '');
    const resultado = norm(a?.resultado || '');
    const statusPromessa = norm(a?.statusPromessa || '');
    const texto = [estagioNorm,tipo,resultado,statusPromessa,norm(a?.proximaAcao||'')].join(' ');
    const isPagamento = tipo.includes('pagamento realizado') || tipo === 'pago' || resultado.includes('pagamento realizado') || resultado.includes('pagamento confirmado') || estagioNorm === 'pago';
    if(isPagamento) return 'Pago';
    if(estagioNorm === 'judicializado' || texto.includes('judicializado') || texto.includes('processo')) return 'Judicializado';
    if(estagioNorm === 'juridico' || estagioNorm === 'jurídico' || texto.includes('juridico') || texto.includes('jurídico')) return 'Jurídico';
    if(estagioNorm === 'protestado' || texto.includes('protestado') || texto.includes('protesto') || texto.includes('cartorio') || texto.includes('cartório')) return 'Protestado';
    if(estagioNorm.includes('revisar pagamento') || tipo.includes('revisar pagamento') || resultado.includes('revisar pagamento') || texto.includes('comprovante')) return 'Revisar pagamento';
    if(estagioNorm === 'negociacao' || estagioNorm === 'negociação' || estagioNorm === 'negociando' || tipo.includes('negociacao') || tipo.includes('negociação') || resultado.includes('negociando')) return 'Negociação';
    if(estagioNorm === 'promessa' || resultado.includes('prometeu') || statusPromessa.includes('aguardando')) return 'Promessa';
    return 'Em contato';
  }
  function kanbanStageTicket(a){
    const st = statusVisualTicket(a);
    return CRM_ESTAGIOS_FLUXO.includes(st) ? st : 'Em contato';
  }
  function kanbanTipoEvolucaoPorDestino(destino){
    if(destino === 'Promessa') return 'promessa';
    if(destino === 'Negociação') return 'negociacao';
    if(destino === 'Protestado') return 'protestado';
    if(destino === 'Jurídico') return 'juridico';
    if(destino === 'Judicializado') return 'judicializado';
    if(destino === 'Revisar pagamento') return 'revisar';
    if(destino === 'Pago') return 'pago';
    return 'contato';
  }
  function kanbanLabelDestino(destino){
    return destino;
  }

  function normalizarTicketsCRM(){
    // Regra: o registro mais antigo do CRM é sempre o Ticket #0.
    // Como novas ações são inseridas no início da lista, a ordem antiga -> nova é a lista invertida.
    [...acoes].reverse().forEach((a, numero)=>{ a.ticketNumero = numero; a.ticket = numero; });
  }
  function ticketLabel(a){
    normalizarTicketsCRM();
    const n = Number.isFinite(Number(a && a.ticketNumero)) ? Number(a.ticketNumero) : 0;
    return 'Ticket #' + n;
  }
  function htm(s){
    return String(s == null ? '' : s).replace(/[&<>"']/g, ch => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[ch]));
  }
  function crmClientePorAcao(a){
    const clientes = agrupar();
    return clientes.find(c => (a.clienteKey && clienteKey(c) === a.clienteKey) || (a.codcli && String(c.codcli) === String(a.codcli)) || norm(c.cliente) === norm(a.cliente));
  }
  function crmDuplicatasDaAcao(a, c){
    const todas = c && Array.isArray(c.duplicatas) ? c.duplicatas : [];
    const selecionadas = Array.isArray(a.duplicatasSelecionadas) ? a.duplicatasSelecionadas : [];
    if(!selecionadas.length) return todas;
    const ids = new Set(selecionadas.map(d=>String(d.id || d.duplicata || d.fatura || d.pedido || '').trim()).filter(Boolean));
    return todas.filter(d=>ids.has(String(idRegistro(d)).trim()) || ids.has(String(d.duplicata||'').trim()) || ids.has(String(d.fatura||'').trim()) || ids.has(String(d.pedido||'').trim()));
  }
  function crmResumoDuplicatasTexto(dups,tipoResumo="contato"){
    const lista = Array.isArray(dups) ? dups : [];
    if(!lista.length) return '';
    const total = lista.reduce((s,d)=>s + (Number(d.valor)||0), 0);
    const linhas = lista.map((d, i)=>`${i + 1}. Duplicata ${d.duplicata || '-'} | Fatura ${d.fatura || '-'} | Pedido ${d.pedido || '-'} | Venc.: ${d.vencimento || '-'} | ${money(d.valor||0)}`);
    let titulo='Duplicatas a negociar';
    if(tipoResumo==='promessa') titulo='Duplicatas em negociação';
    if(tipoResumo==='negociacao') titulo='Duplicatas negociadas';
    if(tipoResumo==='pago') titulo='Duplicatas pagas';
    return `\n\n${titulo} (${lista.length}):\n${linhas.join('\n')}\n\nTotal selecionado: ${money(total)}`;
  }
  function crmMensagemWhatsApp(a){
    const c = crmClientePorAcao(a);
    const dups = crmDuplicatasDaAcao(a, c);
    const totalSelecionado = dups.length ? dups.reduce((s,d)=>s+(Number(d.valor)||0),0) : Number(a.totalSelecionado || a.promessaValor || (c ? c.total : 0));
    const total = money(totalSelecionado || 0);
    const tipo = norm([a.tipo, a.resultado, a.statusNegociacao, a.statusPromessa, a.proximaAcao].filter(Boolean).join(' '));
    let tipoResumo='contato';
    if(tipo.includes('pagamento realizado') || tipo.includes('pago')) tipoResumo='pago';
    else if(tipo.includes('prometeu pagamento') || tipo.includes('promessa')) tipoResumo='promessa';
    else if(tipo.includes('negociando') || tipo.includes('negociacao') || tipo.includes('negociação')) tipoResumo='negociacao';
    const resumoDups = crmResumoDuplicatasTexto(dups,tipoResumo);
    const dataPromessa = a.dataPromessa ? crmDataBR(a.dataPromessa) : '';
    const prox = a.proximaData ? `${crmDataBR(a.proximaData)}${a.proximaHora ? ' às ' + a.proximaHora : ''}` : '';

    if(tipo.includes('pagamento realizado') || tipo.includes('pago') || tipo.includes('cumprida') || tipo.includes('cumprido')){
      return `Olá, ${a.cliente}. Confirmamos o registro do pagamento/regularização referente às duplicatas negociadas.${resumoDups}

Agradecemos o retorno e seguimos à disposição.`;
    }
    if(tipo.includes('prometeu pagamento') || tipo.includes('promessa') || tipo.includes('aguardando')){
      const data = dataPromessa || 'data combinada';
      const valor = Number(a.promessaValor||0) > 0 ? money(a.promessaValor) : total;
      return `Olá, ${a.cliente}. Conforme nossa conversa, ficou registrada a promessa de pagamento para ${data}, no valor de ${valor}.${resumoDups}

Pedimos a gentileza de nos enviar o comprovante assim que o pagamento for realizado.`;
    }
    if(tipo.includes('vencida')){
      return `Olá, ${a.cliente}. Identificamos que a promessa de pagamento registrada para ${dataPromessa || 'a data combinada'} ainda está pendente.${resumoDups}

Poderia nos retornar com uma nova previsão de regularização?`;
    }
    if(tipo.includes('negociando') || tipo.includes('negociacao') || tipo.includes('negociação')){
      return `Olá, ${a.cliente}. Conforme alinhado, estamos dando sequência à negociação dos títulos em aberto.${resumoDups}

Próximo retorno agendado: ${prox || 'a combinar'}.`;
    }
    if(tipo.includes('bloqueio') || tipo.includes('bloque')){
      return `Olá, ${a.cliente}. Consta pendência financeira em aberto no valor de ${total}. Para análise de novos pedidos, precisamos alinhar a regularização dos títulos vencidos.${resumoDups}`;
    }
    return `Olá, ${a.cliente}. Tudo bem? Identificamos títulos vencidos em aberto no valor de ${total}.${resumoDups}

Poderia nos retornar para alinharmos a negociação?`;
  }
  function crmCopiarWhatsApp(idx){
    const a = acoes[idx];
    if(!a) return;
    const texto = crmMensagemWhatsApp(a);
    const done = ()=>mostrarToastCrm('Mensagem de WhatsApp copiada.');
    if(navigator.clipboard && navigator.clipboard.writeText){ navigator.clipboard.writeText(texto).then(done).catch(()=>alert(texto)); }
    else alert(texto);
  }
  function mostrarToastCrm(txt){
    const old = document.querySelector('.toast-crm');
    if(old) old.remove();
    const div = document.createElement('div');
    div.className = 'toast-crm';
    div.textContent = txt;
    document.body.appendChild(div);
    setTimeout(()=>div.remove(), 2200);
  }


  function crmTipoTexto(a){
    return norm([a?.tipo, a?.proximaAcao, a?.resultado, a?.statusNegociacao].filter(Boolean).join(' '));
  }
  function crmAcoesRapidasHtml(a, idx){
    if(!a || acaoExcluida(a)) return '';
    const texto = crmTipoTexto(a);
    const estagio = norm(a.statusNegociacao || '');
    const tipo = norm(a.tipo || '');
    const resultado = norm(a.resultado || '');
    const statusPromessa = norm(a.statusPromessa || '');
    let html = '';

    // O estágio do ticket deve prevalecer sobre a próxima ação.
    // Ex.: uma Promessa com próxima ação "Ligação" não pode exibir os botões de Ligação.
    const ePago = tipo.includes('pagamento realizado') || resultado.includes('pagamento realizado') || resultado.includes('pagamento confirmado') || (estagio === 'pago' && (tipo.includes('pagamento') || resultado.includes('pagamento')));
    const ePromessa = !ePago && (estagio === 'promessa' || resultado.includes('prometeu') || statusPromessa.includes('aguardando') || (estagio === 'pago' && resultado.includes('prometeu')));
    const eNegociacao = !ePago && !ePromessa && (estagio === 'negociacao' || estagio === 'negociação' || estagio === 'negociando' || tipo.includes('negociacao') || tipo.includes('negociação') || resultado.includes('negociando'));
    const eLigacao = !ePago && !ePromessa && !eNegociacao && (estagio === 'em contato' || estagio === 'novos' || tipo.includes('ligacao') || tipo.includes('ligação') || tipo.includes('whatsapp') || tipo.includes('retorno'));
    if(eLigacao){
      html += `<button class="crm-mini-btn success" data-crm-evoluir="promessa" data-crm-idx="${idx}" title="Criar uma promessa vinculada a este ticket">Promessa</button>`;
      html += `<button class="crm-mini-btn" data-crm-evoluir="negociacao" data-crm-idx="${idx}" title="Criar uma negociação vinculada a este ticket">Negociar</button>`;
    }
    if(ePromessa && !ePago){
      html += `<button class="crm-mini-btn success" data-crm-evoluir="pago" data-crm-idx="${idx}" title="Confirmar pagamento vinculado a esta promessa">Pago</button>`;
      html += `<button class="crm-mini-btn" data-crm-evoluir="negociacao" data-crm-idx="${idx}" title="Converter esta promessa em negociação">Negociar</button>`;
    }
    if(eNegociacao && !ePago){
      html += `<button class="crm-mini-btn success" data-crm-evoluir="pago" data-crm-idx="${idx}" title="Registrar pagamento vinculado a este ticket">Pago</button>`;
    }
    return html;
  }

  function crmConfigEvolucao(tipo){
    const hoje = new Date().toISOString().slice(0,10);
    if(tipo === 'promessa') return {
      titulo:'Criar promessa a partir do ticket', tipo:'WhatsApp', resultado:'Prometeu pagamento', estagio:'Promessa', statusPromessa:'Aguardando', proximaAcao:'Retorno', obs:'Cliente retornou e registramos promessa de pagamento.', dataPromessa:hoje
    };
    if(tipo === 'negociacao') return {
      titulo:'Criar negociação a partir do ticket', tipo:'Negociação', resultado:'Negociação', estagio:'Negociação', statusPromessa:'', proximaAcao:'Retorno', obs:'Cliente entrou em negociação para regularização das duplicatas selecionadas.', dataPromessa:''
    };
    if(tipo === 'protestado') return {
      titulo:'Enviar para protesto', tipo:'Protesto', resultado:'Protestado', estagio:'Protestado', statusPromessa:'', proximaAcao:'Acionar jurídico', obs:'Cliente encaminhado para protesto conforme política de cobrança.', dataPromessa:''
    };
    if(tipo === 'juridico') return {
      titulo:'Encaminhar para jurídico', tipo:'Jurídico', resultado:'Encaminhado jurídico', estagio:'Jurídico', statusPromessa:'', proximaAcao:'Acompanhar processo', obs:'Cliente encaminhado para análise jurídica.', dataPromessa:''
    };
    if(tipo === 'judicializado') return {
      titulo:'Marcar como judicializado', tipo:'Judicializado', resultado:'Judicializado', estagio:'Judicializado', statusPromessa:'', proximaAcao:'Acompanhar processo', obs:'Cobrança judicializada. Registrar dados do processo na observação.', dataPromessa:''
    };
    if(tipo === 'revisar') return {
      titulo:'Enviar para revisão de pagamento', tipo:'Revisar pagamento', resultado:'Pagamento realizado', estagio:'Revisar pagamento', statusPromessa:'Aguardando', proximaAcao:'Revisar pagamento', obs:'Pagamento informado pelo cliente. Conferir comprovante e validar baixa financeira.', dataPromessa:hoje
    };
    if(tipo === 'contato') return {
      titulo:'Atualizar contato do ticket', tipo:'Retorno', resultado:'Não respondeu', estagio:'Em contato', statusPromessa:'', proximaAcao:'Retorno', obs:'Atualização de contato do cliente.', dataPromessa:''
    };
    return {
      titulo:'Confirmar pagamento a partir do ticket', tipo:'Pagamento realizado', resultado:'Pagamento realizado', estagio:'Pago', statusPromessa:'Cumprida', proximaAcao:'Revisar pagamento', obs:'Pagamento confirmado para as duplicatas selecionadas.', dataPromessa:hoje
    };
  }

  function abrirModalEvoluirTicket(idx, tipoEvolucao){
    normalizarTicketsCRM();
    const origem = acoes[idx];
    if(!origem || acaoExcluida(origem)) return;
    const cliente = crmClientePorAcao(origem);
    if(!cliente){ alert('Não foi possível localizar o cliente deste ticket na carteira.'); return; }
    const cfg = crmConfigEvolucao(tipoEvolucao);
    const hojeIso = new Date().toISOString().slice(0,10);
    const agora = new Date().toTimeString().slice(0,5);
    const dupsCliente = [...(cliente.duplicatas || [])].sort((a,b)=>(b.dias||0)-(a.dias||0) || (Number(b.valor)||0)-(Number(a.valor)||0));
    const dupsOrigem = crmDuplicatasDaAcao(origem, cliente);
    const idsOrigem = new Set((dupsOrigem.length ? dupsOrigem : dupsCliente).map(d=>String(idRegistro(d))));
    const totalInicial = (dupsOrigem.length ? dupsOrigem : dupsCliente).reduce((s,d)=>s+(Number(d.valor)||0),0);
    $('modalContent').innerHTML = `<p class="eyebrow">Evolução de ticket</p>
      <h2>${htm(cfg.titulo)}</h2>
      <p>Origem: <strong>${htm(ticketLabel(origem))}</strong> • Cliente: <strong>${htm(cliente.cliente)}</strong>. O novo registro ficará vinculado ao ticket original.</p>
      <form id="formEvoluirTicket" class="action-form">
        <div class="form-section-title">Dados da nova ação</div>
        ${responsavelSelectHtml('evo', origem.responsavel || usuarioAtualEmail() || 'Usuário')}
        <label class="form-field"><span>Tipo de ação *</span><select id="evoTipo" required>${opcoesHtml(CRM_TIPOS_ACAO, cfg.tipo)}</select></label>
        <label class="form-field"><span>Data *</span><input id="evoData" type="date" value="${hojeIso}" required /></label>
        <label class="form-field"><span>Hora</span><input id="evoHora" type="time" value="${agora}" /></label>
        <label class="form-field"><span>Resultado *</span><select id="evoResultado" required>${opcoesHtml(CRM_RESULTADOS, cfg.resultado)}</select></label>
        <label class="form-field"><span>Estágio *</span><select id="evoEstagio" required>${opcoesHtml(CRM_ESTAGIOS_FLUXO, cfg.estagio)}</select></label>
        <div class="form-section-title">Duplicatas vinculadas</div>
        <div id="evoDuplicatasBox" class="crm-dup-box"></div>
        <div id="evoPromessaSection" class="promise-fields" style="display:none">
          <div class="form-section-title">Promessa / negociação</div>
          <label class="form-field"><span>Valor prometido / negociado</span><input id="evoPromessaValor" type="number" min="0" step="0.01" value="${totalInicial ? totalInicial.toFixed(2) : ''}" /></label>
          <label class="form-field"><span>Data prometida / pagamento</span><input id="evoPromessaData" type="date" value="${htm(cfg.dataPromessa || '')}" /></label>
          <label class="form-field"><span>Status</span><select id="evoPromessaStatus"><option value="">Sem promessa</option>${['Aguardando','Vencida','Cumprida'].map(v=>`<option ${cfg.statusPromessa===v?'selected':''}>${v}</option>`).join('')}</select></label>
        </div>
        <div class="form-section-title">Próxima ação</div>
        <label class="form-field"><span>Próxima ação *</span><select id="evoProxima" required>${opcoesHtml(CRM_PROXIMAS_ACOES, cfg.proximaAcao)}</select></label>
        <label class="form-field"><span>Data da próxima ação *</span><input id="evoProximaData" type="date" value="${hojeIso}" required /></label>
        <label class="form-field"><span>Hora da próxima ação *</span><input id="evoProximaHora" type="time" value="14:00" required /></label>
        <label class="form-field full"><span>Observação *</span><textarea id="evoObs" rows="4" required>${htm(cfg.obs)}</textarea></label>
        <div id="evoErro" class="form-error" role="alert"></div>
        <div class="modal-actions-row"><button type="submit" id="btnSalvarEvolucao">Salvar evolução</button><button type="button" class="secondary" id="btnCancelarEvolucao">Cancelar</button></div>
      </form>`;
    $('modal').classList.add('open');
    const box = $('evoDuplicatasBox');
    function renderDups(){
      if(!dupsCliente.length){ box.innerHTML = '<div class="crm-dup-empty">Cliente sem duplicatas em aberto.</div>'; return; }
      box.innerHTML = `<div class="crm-dup-head"><div><strong>Duplicatas da negociação</strong><small>${dupsCliente.length} título(s)</small></div><label class="inline-check"><input type="checkbox" id="evoSelecionarTodasDups" /> selecionar todas</label></div><div class="crm-dup-list">${dupsCliente.map(d=>{ const id=String(idRegistro(d)); const checked=idsOrigem.has(id) ? 'checked' : ''; return `<label class="crm-dup-item"><input type="checkbox" class="evoDupCheck" value="${htm(id)}" ${checked} data-valor="${Number(d.valor)||0}" /><span><b>Dup. ${htm(d.duplicata || '-')}</b><small>Fatura ${htm(d.fatura || '-')} • Pedido ${htm(d.pedido || '-')} • Venc. ${htm(d.vencimento || '-')} • ${d.dias || 0} dias</small></span><strong>${money(d.valor||0)}</strong></label>`; }).join('')}</div><div id="evoDupResumo" class="crm-dup-summary"></div>`;
      const checks = Array.from(box.querySelectorAll('.evoDupCheck'));
      const all = $('evoSelecionarTodasDups');
      const resumo = $('evoDupResumo');
      function atualiza(){
        const marcadas = checks.filter(ch=>ch.checked);
        const valor = marcadas.reduce((s,ch)=>s+(Number(ch.dataset.valor)||0),0);
        if(resumo) resumo.textContent = `${marcadas.length} duplicata(s) selecionada(s) • ${money(valor)}`;
        const campo = $('evoPromessaValor');
        const est = $('evoEstagio');
        if(campo && est && ['promessa','negociacao'].includes(norm(est.value || ''))) campo.value = valor > 0 ? valor.toFixed(2) : '';
        if(all) all.checked = checks.length>0 && checks.every(ch=>ch.checked);
      }
      if(all) all.onchange = ()=>{ checks.forEach(ch=>ch.checked=all.checked); atualiza(); };
      checks.forEach(ch=>ch.onchange = atualiza);
      atualiza();
    }
    renderDups();
    function atualizarSecaoPromessaEvo(){
      const est = $('evoEstagio'); const box = $('evoPromessaSection');
      if(!est || !box) return;
      const estagioNorm = norm(est.value || '');
      const promessaObrigatoria = estagioNorm === 'promessa';
      const mostrar = promessaObrigatoria || estagioNorm === 'negociacao';
      box.style.display = mostrar ? '' : 'none';
      if($('evoPromessaValor')) $('evoPromessaValor').required = promessaObrigatoria;
      if($('evoPromessaData')) $('evoPromessaData').required = promessaObrigatoria;
      if($('evoPromessaStatus') && mostrar && !$('evoPromessaStatus').value) $('evoPromessaStatus').value = promessaObrigatoria ? 'Aguardando' : '';
      if(!mostrar){
        if($('evoPromessaValor')) $('evoPromessaValor').value = '';
        if($('evoPromessaData')) $('evoPromessaData').value = '';
        if($('evoPromessaStatus')) $('evoPromessaStatus').value = '';
      }
    }
    if($('evoEstagio')) $('evoEstagio').addEventListener('change', atualizarSecaoPromessaEvo);
    atualizarSecaoPromessaEvo();
    configurarResponsavelSelect('evo');
    $('btnCancelarEvolucao').onclick = ()=>$('modal').classList.remove('open');
    let evolucaoSalvando = false;
    $('formEvoluirTicket').onsubmit = async e=>{
      e.preventDefault();
      if(evolucaoSalvando) return;
      evolucaoSalvando = true;
      const btnEvo = $('btnSalvarEvolucao');
      if(btnEvo){ btnEvo.disabled = true; btnEvo.textContent = 'Salvando...'; }
      const obs = String($('evoObs').value||'').trim();
      if(!validarResponsavelSelect('evo','evoErro')){ evolucaoSalvando=false; if(btnEvo){ btnEvo.disabled=false; btnEvo.textContent='Salvar evolução'; } return; }
      if(!obs){ $('evoErro').textContent='Informe a observação.'; evolucaoSalvando=false; if(btnEvo){ btnEvo.disabled=false; btnEvo.textContent='Salvar evolução'; } return; }
      const checks = Array.from(document.querySelectorAll('.evoDupCheck:checked'));
      const duplicatasSelecionadas = checks.map(ch=>{ const d = dupsCliente.find(x=>String(idRegistro(x))===String(ch.value)) || {}; return { id: ch.value, duplicata: d.duplicata || '', fatura: d.fatura || '', pedido: d.pedido || '', vencimento: d.vencimento || '', valor: Number(d.valor)||0, dias: Number(d.dias)||0 }; });
      const totalSelecionado = duplicatasSelecionadas.reduce((s,d)=>s+(Number(d.valor)||0),0);
      const evoEstagioNorm = norm($('evoEstagio').value || '');
      const evoPromessaObrigatoria = evoEstagioNorm === 'promessa';
      const evoPromessaPermitida = evoPromessaObrigatoria || evoEstagioNorm === 'negociacao';
      if(evoPromessaObrigatoria && !num($('evoPromessaValor').value)){ $('evoErro').textContent='Informe o valor da promessa de pagamento.'; evolucaoSalvando=false; if(btnEvo){ btnEvo.disabled=false; btnEvo.textContent='Salvar evolução'; } return; }
      if(evoPromessaObrigatoria && !$('evoPromessaData').value){ $('evoErro').textContent='Informe a data prometida da promessa de pagamento.'; evolucaoSalvando=false; if(btnEvo){ btnEvo.disabled=false; btnEvo.textContent='Salvar evolução'; } return; }
      const carimboCriacao = carimboAgoraLocal();
      const nova = {
        criadoEm: carimboCriacao.iso, criadoEmMs: carimboCriacao.ms, criadoEmData: carimboCriacao.data, criadoEmHora: carimboCriacao.hora, data:$('evoData').value, hora:$('evoHora').value,
        codcli: cliente.codcli || '', cliente: cliente.cliente, clienteKey: clienteKey(cliente), responsavel: obterResponsavelSelect('evo') || 'Usuário',
        tipo:$('evoTipo').value, resultado:$('evoResultado').value, statusNegociacao:$('evoEstagio').value,
        promessaValor: evoPromessaPermitida ? (num($('evoPromessaValor').value) || 0) : 0, dataPromessa:evoPromessaPermitida ? $('evoPromessaData').value : '', statusPromessa:evoPromessaPermitida ? ($('evoPromessaStatus').value || (evoPromessaObrigatoria ? 'Aguardando' : '')) : '',
        duplicatasSelecionadas, totalSelecionado, proximaAcao:$('evoProxima').value, proximaData:$('evoProximaData').value, proximaHora:$('evoProximaHora').value,
        obs, ticketOrigemCloudId: origem.cloudId || '', ticketOrigemLabel: ticketLabel(origem), criadoPor: usuarioAtualEmail()
      };
      const statusDestino = $('evoEstagio').value;
      // Mantém o ticket de origem com seu estágio original.
      // Ex.: Promessa continua como Promessa; ao confirmar pagamento, cria um novo ticket Pago vinculado.
      origem.evoluidoPara = statusDestino;
      origem.evoluidoEm = new Date().toLocaleString('pt-BR');
      origem.evoluidoPor = usuarioAtualEmail();
      try{
        await salvarAcaoNuvem(origem);
        await salvarAcaoNuvem(nova);
      }catch(err){ console.error('Erro ao salvar evolução:', err); $('evoErro').textContent = 'Erro ao salvar na nuvem: ' + (err && (err.code || err.message) ? (err.code || err.message) : 'verifique conexão e permissões.'); evolucaoSalvando=false; if(btnEvo){ btnEvo.disabled=false; btnEvo.textContent='Salvar evolução'; } return; }
      // Não adiciona localmente: o snapshot do Firestore atualiza a tela e evita duplicidade.
      $('modal').classList.remove('open');
      mostrarToastCrm('Evolução do ticket salva.');
    };
  }

  function aplicarFiltrosKanbanDom(){
    const body = $('kanbanBody');
    if(!body) return;
    const globalTerm = norm(kanbanBusca || '');
    body.querySelectorAll('.kanban-col').forEach(col=>{
      const stage = col.dataset.kanbanStage || '';
      const colTerm = norm(kanbanColBusca[stage] || '');
      let visibleCount = 0;
      col.querySelectorAll('.kanban-card-item').forEach(card=>{
        const txt = card.dataset.kanbanSearch || norm(card.textContent || '');
        const ok = (!globalTerm || txt.includes(globalTerm)) && (!colTerm || txt.includes(colTerm));
        card.style.display = ok ? '' : 'none';
        if(ok) visibleCount++;
      });
      const counter = col.querySelector('h4 span');
      if(counter) counter.textContent = visibleCount;
      const empty = col.querySelector('.kanban-empty');
      if(empty) empty.style.display = visibleCount ? 'none' : '';
    });
  }


  function renderTimelineCrm(){
    const body = $('timelineBody');
    if(!body) return;
    const termoTimeline = norm(timelineBusca || '');
    const base = acoes.map((a, originalIdx)=>({ a, originalIdx }));
    const filtradas = termoTimeline
      ? base.filter(({a})=>{
          const textoBusca = a._timelineSearch || norm([a.cliente, a.codcli, a.responsavel, a.obs, a.resultado, a.tipo, a.estagio, ticketLabel(a)].join(' '));
          a._timelineSearch = textoBusca;
          return textoBusca.includes(termoTimeline);
        })
      : base;
    const acoesTimeline = filtradas.slice(0,60);
    body.innerHTML = acoesTimeline.map(({a, originalIdx})=>{
      const excluida = acaoExcluida(a);
      const statusTxt = statusVisualTicket(a);
      const extraExcl = excluida ? `<small class="timeline-deleted-note">Excluído em ${htm(a.excluidoEm||'-')}${a.motivoExclusao ? ' • Motivo: ' + htm(a.motivoExclusao) : ''}</small>` : '';
      const registro = crmDataHoraRegistro(a);
      return `<div class="timeline-item timeline-readable ${excluida?'deleted':''}">
        <strong class="timeline-date-block"><span>${htm(registro.data)}</span><small>${htm(registro.hora)}</small></strong>
        <div class="timeline-main crm-readable-card">
          <div class="readable-title"><span class="ticket-badge">${htm(ticketLabel(a))}</span><strong>${htm(a.cliente)}</strong></div>
          <div class="readable-chips"><span>${htm(a.tipo || 'Ação')}</span><span>${htm(statusTxt)}</span><span>${htm(a.responsavel||'Usuário')}</span></div>
          ${a.resultado ? `<div class="readable-result">${htm(a.resultado)}</div>` : ''}
          ${a.obs ? `<div class="readable-observation">${htm(a.obs)}</div>` : ''}
          ${extraExcl}
        </div>
        <div class="crm-actions"><span class="score ${excluida?'s-critico':'s-atencao'}">${htm(statusTxt)}</span>${!excluida ? `${crmAcoesRapidasHtml(a, originalIdx)}<button class="crm-mini-btn" data-crm-whatsapp="${originalIdx}">WhatsApp</button><button class="crm-mini-btn" data-crm-edit="${originalIdx}">Editar</button><button class="crm-mini-btn danger" data-crm-delete="${originalIdx}">Excluir</button>` : ''}</div>
      </div>`;
    }).join('') || (termoTimeline ? '<p>Nenhuma ação encontrada para essa pesquisa.</p>' : '<p>Sem ações registradas.</p>');
  }

  function renderCrm(){
    if(acoes.length===0){
      const clientesDemo = agrupar();
      const c1 = clientesDemo[0]; const c2 = clientesDemo[1]; const c3 = clientesDemo[2];
      acoes = [
        {data:new Date().toISOString().slice(0,10), hora:'08:30', cliente:c1?.cliente || 'Grupo Elegance', codcli:c1?.codcli || '', clienteKey:c1?clienteKey(c1):'', responsavel:'Juliana', tipo:'Ligação', resultado:'Não atendeu', statusNegociacao:'Em contato', proximaAcao:'WhatsApp', proximaData:new Date().toISOString().slice(0,10), proximaHora:'14:00', obs:'Prioridade máxima: negociar entrada e travar novos pedidos até acordo.'},
        {data:new Date().toISOString().slice(0,10), hora:'10:00', cliente:c2?.cliente || 'Loja Imperial Moda', codcli:c2?.codcli || '', clienteKey:c2?clienteKey(c2):'', responsavel:'Juliana', tipo:'WhatsApp', resultado:'Prometeu pagamento', statusNegociacao:'Promessa', dataPromessa:new Date().toISOString().slice(0,10), promessaValor:12000, statusPromessa:'Aguardando', proximaAcao:'Retorno', proximaData:new Date().toISOString().slice(0,10), proximaHora:'16:00', obs:'Enviar segunda via das duplicatas e proposta de parcelamento.'},
        {data:'2026-06-20', hora:'09:00', cliente:c3?.cliente || 'Comercial Silva', codcli:c3?.codcli || '', clienteKey:c3?clienteKey(c3):'', responsavel:'Gisele', tipo:'Retorno', resultado:'Negociação', statusNegociacao:'Negociação', dataPromessa:'2026-06-21', promessaValor:8500, statusPromessa:'Vencida', proximaAcao:'Ligação', proximaData:new Date().toISOString().slice(0,10), proximaHora:'11:30', obs:'Cliente prometeu retorno após conferência com financeiro.'}
      ];
    }
    normalizarTicketsCRM();
    const operacionais = acoes.filter(a=>!acaoExcluida(a));
    const totalPromessas = operacionais.reduce((s,a)=>s+(Number(a.promessaValor)||0),0);
    const promessasVencidas = operacionais.filter(a=>crmClassificar({data:a.dataPromessa||a.proximaData||a.data,statusAcao:a.statusPromessa})==='atrasada' || String(a.statusPromessa||'').toLowerCase().includes('venc'));
    const hoje = operacionais.filter(a=>crmClassificar(a)==='hoje');
    const atrasadas = operacionais.filter(a=>crmClassificar(a)==='atrasada');
    const concluidas = operacionais.filter(a=>crmClassificar(a)==='concluida' || crmChecklistCompleto(a));
    const minhas = operacionais.filter(a=>{ const email = norm(usuarioAtualEmail()); return norm(a.responsavel||'').includes(email) || norm(a.usuario||'').includes(email) || norm(a.criadoPor||'').includes(email) || norm(a.atualizadoPor||'').includes(email); });
    const promessasCount = operacionais.filter(a=>statusVisualTicket(a)==='Promessa').length;
    const pendentes = operacionais.filter(a=>crmClassificar(a)!=='concluida' && !crmChecklistCompleto(a));
    const progressoDia = (hoje.length + atrasadas.length + concluidas.length) ? Math.round((concluidas.length / (hoje.length + atrasadas.length + concluidas.length)) * 100) : 0;
    if($('crmResumoBody')) $('crmResumoBody').innerHTML = `
      <div class="crm-kpi danger"><small>Atrasadas</small><strong>${atrasadas.length}</strong><span>Ações vencidas</span></div>
      <div class="crm-kpi warning"><small>Para hoje</small><strong>${hoje.length}</strong><span>Retornos e contatos</span></div>
      <div class="crm-kpi"><small>Promessas em aberto</small><strong>${money(totalPromessas)}</strong><span>${operacionais.filter(a=>a.promessaValor).length} compromisso(s)</span></div>
      <div class="crm-kpi success"><small>Concluídas</small><strong>${concluidas.length}</strong><span>${progressoDia}% do fluxo do dia</span></div>`;

    const ordenadas = [...operacionais].sort((a,b)=>(crmDateObj(a.proximaData||a.data)?.getTime()||0)-(crmDateObj(b.proximaData||b.data)?.getTime()||0));
    const baseAgenda = ordenadas.filter(a=>['atrasada','hoje'].includes(crmClassificar(a))).concat(ordenadas.filter(a=>crmClassificar(a)==='futura')).concat(ordenadas.filter(a=>crmClassificar(a)==='concluida'));
    const contadoresAgenda = {
      todas: baseAgenda.length, pendentes: pendentes.length, hoje: hoje.length, atrasadas: atrasadas.length, promessas: promessasCount, concluidas: concluidas.length, minhas: minhas.length
    };
    if($('crmAgendaFiltros')) $('crmAgendaFiltros').innerHTML = crmAgendaFiltrosHtml(contadoresAgenda);

    const agenda = crmFiltrarAgenda(baseAgenda).slice(0,120);
    const agendaConcluida = a => crmClassificar(a)==='concluida' || crmChecklistCompleto(a) || statusVisualTicket(a)==='Pago';
    const agendaPendentesBase = agenda.filter(a=>!agendaConcluida(a));
    const agendaConcluidasBase = agenda.filter(a=>agendaConcluida(a));
    const agendaMatchBusca = (a, termo) => {
      const q = norm(termo || '');
      if(!q) return true;
      return norm([a.cliente, a.codcli, ticketLabel(a), a.responsavel, a.tipo, a.resultado, a.statusNegociacao, a.obs].filter(Boolean).join(' ')).includes(q);
    };
    const agendaPendentes = agendaPendentesBase.filter(a=>agendaMatchBusca(a, agendaBuscaPendentes));
    const agendaConcluidas = agendaConcluidasBase.filter(a=>agendaMatchBusca(a, agendaBuscaConcluidos));
    const totalAgendaDia = agendaPendentes.length + agendaConcluidas.length;
    const pctAgenda = totalAgendaDia ? Math.round((agendaConcluidas.length / totalAgendaDia) * 100) : 0;
    const promessasAgenda = agenda.filter(a=>statusVisualTicket(a)==='Promessa').length;
    const negociacoesAgenda = agenda.filter(a=>statusVisualTicket(a)==='Negociação').length;
    const pagosAgenda = agenda.filter(a=>statusVisualTicket(a)==='Pago').length;
    const atrasadasAgenda = agenda.filter(a=>crmClassificar(a)==='atrasada').length;

    if($('agendaOperacaoResumo')) $('agendaOperacaoResumo').innerHTML = `
      <div class="agenda-resumo-card info"><small>Tarefas filtradas</small><strong>${totalAgendaDia}</strong><span>${agendaFiltro === 'todas' ? 'Todas as ações' : 'Filtro atual'}</span></div>
      <div class="agenda-resumo-card warning"><small>Pendentes</small><strong>${agendaPendentes.length}</strong><span>Para executar</span></div>
      <div class="agenda-resumo-card success"><small>Concluídas</small><strong>${agendaConcluidas.length}</strong><span>${pctAgenda}% de produtividade</span></div>
      <div class="agenda-resumo-card danger"><small>Atrasadas</small><strong>${atrasadasAgenda}</strong><span>Precisam de prioridade</span></div>`;
    if($('agendaOperacaoProgressoTexto')) $('agendaOperacaoProgressoTexto').textContent = `${agendaConcluidas.length} de ${totalAgendaDia} tarefas`;
    if($('agendaOperacaoProgressoPct')) $('agendaOperacaoProgressoPct').textContent = `${pctAgenda}%`;
    if($('agendaOperacaoProgressoBar')) $('agendaOperacaoProgressoBar').style.width = `${pctAgenda}%`;
    if($('agendaPendentesCount')) $('agendaPendentesCount').textContent = agendaPendentes.length;
    if($('agendaConcluidosCount')) $('agendaConcluidosCount').textContent = agendaConcluidas.length;
    if($('agendaPendentesSearch')) $('agendaPendentesSearch').value = agendaBuscaPendentes;
    if($('agendaConcluidosSearch')) $('agendaConcluidosSearch').value = agendaBuscaConcluidos;

    const agendaCardHtml = (a)=>{
      const idx = acoes.indexOf(a); const cls=crmClassificar(a); const c=crmClientePorAcao(a); const prog=crmChecklistProgresso(a);
      const valor = Number(a.promessaValor)||Number(a.totalSelecionado)||Number(c?.total)||0;
      const dupCount = Array.isArray(a.duplicatasSelecionadas) && a.duplicatasSelecionadas.length ? a.duplicatasSelecionadas.length : (c?.duplicatas?.length || 0);
      const prioridade = cls === 'atrasada' ? 'alta' : statusVisualTicket(a)==='Pago' || crmChecklistCompleto(a) ? 'ok' : cls === 'hoje' ? 'media' : 'normal';
      const ultimoContato = a.data ? crmDataBR(a.data) + (a.hora ? ' às ' + a.hora : '') : '-';
      return `<div class="crm-agenda-item agenda-card ${prioridade}">
        <div class="crm-time agenda-time"><strong>${htm(a.proximaHora || a.hora || '--:--')}</strong><small>${crmDataBR(a.proximaData || a.data)}</small></div>
        <div class="crm-main agenda-main crm-readable-card">
          <div class="agenda-title-line readable-title"><span class="ticket-badge">${htm(ticketLabel(a))}</span><strong>${htm(a.cliente)}</strong></div>
          <div class="readable-chips"><span>${htm(statusVisualTicket(a))}</span><span>${htm(a.proximaAcao || a.tipo)}</span><span>${htm(a.responsavel || 'Usuário')}</span><span>${money(valor)}</span><span>${dupCount} duplicata(s)</span></div>
          <div class="readable-info"><strong>Último contato</strong><span>${htm(ultimoContato)}</span></div>
          ${a.resultado ? `<div class="readable-result">${htm(a.resultado)}</div>` : ''}
          ${a.obs ? `<div class="readable-observation">${htm(a.obs)}</div>` : ''}
          ${crmChecklistHtml(a, idx)}
        </div>
        <div class="crm-actions agenda-actions"><span class="promise-status ${cls}">${crmStatusLabel(cls)}</span><span class="agenda-progress-text">${prog.pct}%</span>${crmAcoesRapidasHtml(a, idx)}<button class="crm-mini-btn" data-crm-whatsapp="${idx}">WhatsApp</button></div>
      </div>`;
    };
    if($('agendaPendentesBody')) $('agendaPendentesBody').innerHTML = agendaPendentes.map(agendaCardHtml).join('') || '<p>Sem pendências neste filtro.</p>';
    if($('agendaConcluidosBody')) $('agendaConcluidosBody').innerHTML = agendaConcluidas.map(agendaCardHtml).join('') || '<p>Sem tarefas concluídas neste filtro.</p>';
    if($('crmAgendaBody')) $('crmAgendaBody').innerHTML = agenda.map(agendaCardHtml).join('') || '<p>Sem ações para este filtro.</p>';

    const promessas = operacionais.filter(a=>statusVisualTicket(a)==='Promessa');
    if($('promessasBody')) $('promessasBody').innerHTML = promessas.map(a=>{
      const cls = String(a.statusPromessa||'').toLowerCase().includes('venc') ? 'vencida' : String(a.statusPromessa||'').toLowerCase().includes('cumpr') || String(a.statusPromessa||'').toLowerCase().includes('paga') ? 'cumprida' : crmClassificar({data:a.dataPromessa, statusAcao:a.statusPromessa});
      return `<div class="promise-item">
        <div class="promise-value">${money(a.promessaValor||0)}</div>
        <div class="crm-main"><strong>${htm(a.cliente)}</strong><small>Promessa: ${crmDataBR(a.dataPromessa)} • ${htm(a.responsavel||'Usuário')}</small><small>${htm(a.obs||'')}</small></div>
        <span class="promise-status ${cls}">${htm(a.statusPromessa || crmStatusLabel(cls))}</span>
      </div>`;
    }).join('') || '<p>Nenhuma promessa cadastrada.</p>';

    const kanbanCols = CRM_ESTAGIOS_FLUXO;
    const kanbanTermo = norm(kanbanBusca);
    const responsaveisKanban = [...new Set(operacionais.map(a=>String(a.responsavel||'Usuário').trim()).filter(Boolean))].sort((a,b)=>a.localeCompare(b,'pt-BR'));
    const respSelect = $('kanbanResponsavel');
    if(respSelect){
      const atual = kanbanResponsavel || respSelect.value || '';
      respSelect.innerHTML = '<option value="">Todos responsáveis</option>' + responsaveisKanban.map(r=>`<option value="${htm(r)}" ${r===atual?'selected':''}>${htm(r)}</option>`).join('');
      respSelect.value = atual;
    }
    if($('kanbanBody')) $('kanbanBody').innerHTML = kanbanCols.map(col=>{
      const colKey = norm(col).replace(/[^a-z0-9]+/g,'-');
      const termoColuna = norm(kanbanColBusca[col] || '');
      const itens = operacionais.filter(a=>kanbanStageTicket(a) === col)
        .filter(a=>!kanbanResponsavel || String(a.responsavel||'Usuário') === kanbanResponsavel)
        .filter(a=>!kanbanTermo || norm([a.cliente, a.codcli, a.responsavel, a.obs, ticketLabel(a)].join(' ')).includes(kanbanTermo))
        .filter(a=>!termoColuna || norm([a.cliente, a.codcli, a.responsavel, a.obs, ticketLabel(a)].join(' ')).includes(termoColuna));
      return `<div class="kanban-col kanban-stage-${colKey}" data-kanban-stage="${htm(col)}">
        <h4>${kanbanLabelDestino(col)}<span>${itens.length}</span></h4>
        <input class="kanban-col-search" data-kanban-col-search="${htm(col)}" type="search" placeholder="Pesquisar cliente..." value="${htm(kanbanColBusca[col]||'')}" autocomplete="off" />
        <div class="kanban-dropzone">${itens.map(a=>{
          const idx = acoes.indexOf(a); const c=crmClientePorAcao(a); const valor = Number(a.promessaValor)||Number(a.totalSelecionado)||Number(c?.total)||0;
          const dupCount = Array.isArray(a.duplicatasSelecionadas) && a.duplicatasSelecionadas.length ? a.duplicatasSelecionadas.length : (c?.duplicatas?.length || 0);
          const searchText = norm([a.cliente, a.codcli, a.responsavel, a.obs, ticketLabel(a), a.tipo, a.resultado, a.estagio].join(' '));
          return `<div class="kanban-card-item" draggable="true" data-kanban-idx="${idx}" data-kanban-current="${htm(col)}" data-kanban-search="${htm(searchText)}">
            <div class="kanban-ticket-line"><span class="ticket-badge">${htm(ticketLabel(a))}</span><small>${htm(a.responsavel||'Usuário')}</small></div>
            <strong>${htm(a.cliente)}</strong>
            <small>${money(valor)} • ${dupCount} duplicata(s)</small>
            <small>${htm(a.proximaAcao||a.tipo)} • ${crmDataBR(a.proximaData||a.data)}${a.proximaHora?' às '+htm(a.proximaHora):''}</small>
            <small>${htm(a.obs||'')}</small>
          </div>`;
        }).join('') || '<small class="kanban-empty">Sem tickets neste estágio.</small>'}</div>
      </div>`;
    }).join('');



    aplicarFiltrosKanbanDom();

    renderTimelineCrm();

    const cobradores = {};
    if($('rankingCobDataIni') && !$('rankingCobDataIni').value && $('rankingCobDataFim') && !$('rankingCobDataFim').value){
      rankingCobSetPeriodoMesAtual();
    }
    const operacionaisRanking = operacionais.filter(rankingCobDentroPeriodo);
    if($('rankingCobPeriodoInfo')) $('rankingCobPeriodoInfo').textContent = rankingCobPeriodoTexto();
    operacionaisRanking.forEach(a=>{
      const r = a.responsavel || 'Usuário';
      if(!cobradores[r]) cobradores[r] = {acoes:0, ligacoes:0, whats:0, promessas:0, cumpridas:0, recebido:0};
      const c = cobradores[r];
      c.acoes++;
      if(a.tipo === 'Ligação') c.ligacoes++;
      if(a.tipo === 'WhatsApp') c.whats++;
      if(kanbanStageTicket(a) === 'Promessa' || Number(a.promessaValor) > 0 || norm(a.resultado||'').includes('prometeu')) c.promessas++;
      const textoPagamento = norm([
        a.statusNegociacao,
        a.estagio,
        a.tipo,
        a.resultado,
        a.statusPromessa,
        a.statusAcao,
        a.proximaAcao
      ].filter(Boolean).join(' '));
      const isPago = kanbanStageTicket(a) === 'Pago'
        || textoPagamento.includes('pagamento realizado')
        || textoPagamento.includes('pagamento confirmado')
        || textoPagamento.includes('pago')
        || textoPagamento.includes('paga')
        || textoPagamento.includes('cumprida')
        || textoPagamento.includes('cumprido');
      if(isPago){
        const cli = crmClientePorAcao(a);
        const valorRecebido = Number(a.promessaValor) || Number(a.totalSelecionado) || Number(cli?.total) || 0;
        c.cumpridas++;
        c.recebido += valorRecebido;
      }
    });
    if($('cobradoresBody')) $('cobradoresBody').innerHTML = Object.entries(cobradores).sort((a,b)=>b[1].acoes-a[1].acoes || b[1].recebido-a[1].recebido).map(([nome,d],i)=>`<div class="collector-item"><div class="collector-rank">${i+1}º</div><div class="crm-main"><strong>${htm(nome)}</strong><small>${d.acoes} ação(ões) no período</small></div><div class="collector-metrics"><span>☎ ${d.ligacoes}</span><span>💬 ${d.whats}</span><span>🤝 ${d.promessas}</span><span>✅ ${d.cumpridas}</span><span>${money(d.recebido)}</span></div></div>`).join('') || '<p>Sem ações no período selecionado.</p>';

    const crmEl = $('crm');
    if(crmEl && !crmEl.dataset.crmDelegated){
      crmEl.dataset.crmDelegated = '1';
      // Não atualiza automaticamente enquanto o usuário escolhe/digita datas.
      // Isso evita travamentos e fechamento do calendário do navegador.
      crmEl.addEventListener('change', e=>{
        if(e.target && (e.target.id === 'rankingCobDataIni' || e.target.id === 'rankingCobDataFim')){
          if($('rankingCobPeriodoInfo')) $('rankingCobPeriodoInfo').textContent = 'Clique em Aplicar para atualizar o ranking.';
          return;
        }
      });
      crmEl.addEventListener('click', e=>{
        const aplicarRank = e.target.closest('#btnRankingCobAplicar');
        if(aplicarRank){ renderCrm(); return; }
        const hojeRank = e.target.closest('#btnRankingCobHoje');
        if(hojeRank){ rankingCobSetPeriodoHoje(); renderCrm(); return; }
        const semanaRank = e.target.closest('#btnRankingCobSemana');
        if(semanaRank){ rankingCobSetPeriodoSemanaAtual(); renderCrm(); return; }
        const mesRank = e.target.closest('#btnRankingCobMes');
        if(mesRank){ rankingCobSetPeriodoMesAtual(); renderCrm(); return; }
        const btn = e.target.closest('[data-crm-whatsapp]');
        if(btn) crmCopiarWhatsApp(Number(btn.dataset.crmWhatsapp));
        const edit = e.target.closest('[data-crm-edit]');
        if(edit) abrirModalEditarAcao(Number(edit.dataset.crmEdit));
        const evoluir = e.target.closest('[data-crm-evoluir]');
        if(evoluir) abrirModalEvoluirTicket(Number(evoluir.dataset.crmIdx), evoluir.dataset.crmEvoluir);
        const del = e.target.closest('[data-crm-delete]');
        if(del) excluirAcaoCRM(Number(del.dataset.crmDelete));
        const filtro = e.target.closest('[data-agenda-filter]');
        if(filtro){ agendaFiltro = filtro.dataset.agendaFilter || 'pendentes'; renderCrm(); }
        const full = e.target.closest('#btnExpandirKanban');
        if(full){ kanbanFullscreen = !kanbanFullscreen; document.body.classList.toggle('kanban-fullscreen', kanbanFullscreen); full.textContent = kanbanFullscreen ? '✕ Fechar Kanban' : '⛶ Expandir'; }
      });
      crmEl.addEventListener('input', e=>{
        if(e.target && e.target.id === 'kanbanBusca'){ kanbanBusca = e.target.value || ''; aplicarFiltrosKanbanDom(); }
        if(e.target && e.target.id === 'timelineBusca'){
          timelineBusca = e.target.value || '';
          clearTimeout(timelineBuscaTimer);
          timelineBuscaTimer = setTimeout(renderTimelineCrm, 220);
        }
        if(e.target && e.target.id === 'agendaPendentesSearch'){ agendaBuscaPendentes = e.target.value || ''; renderCrm(); }
        if(e.target && e.target.id === 'agendaConcluidosSearch'){ agendaBuscaConcluidos = e.target.value || ''; renderCrm(); }
        if(e.target && e.target.matches('[data-kanban-col-search]')){ kanbanColBusca[e.target.dataset.kanbanColSearch] = e.target.value || ''; aplicarFiltrosKanbanDom(); }
      });
      crmEl.addEventListener('change', async e=>{
        if(e.target && e.target.id === 'kanbanResponsavel'){ kanbanResponsavel = e.target.value || ''; renderCrm(); return; }
        const chk = e.target.closest('[data-crm-checklist]');
        if(!chk) return;
        const idx = Number(chk.dataset.crmChecklist);
        const item = chk.dataset.checkItem;
        const a = acoes[idx];
        if(!a || !item) return;
        const ck = crmChecklistObj(a);
        ck[item] = !!chk.checked;
        a.checklist = ck;
        a.checklistAtualizadoEm = new Date().toLocaleString('pt-BR');
        a.checklistAtualizadoPor = usuarioAtualEmail();
        try{ await salvarAcaoNuvem(a); }catch(err){ console.error('Erro ao salvar checklist:', err); alert('Não foi possível salvar o checklist na nuvem.'); }
        renderCrm();
      });
      crmEl.addEventListener('dragstart', e=>{
        const card = e.target.closest('[data-kanban-idx]');
        if(!card) return;
        e.dataTransfer.effectAllowed = 'move';
        e.dataTransfer.setData('text/plain', card.dataset.kanbanIdx);
        setTimeout(()=>card.classList.add('dragging'),0);
      });
      crmEl.addEventListener('dragend', e=>{
        const card = e.target.closest('[data-kanban-idx]');
        if(card) card.classList.remove('dragging');
        crmEl.querySelectorAll('.kanban-col.drag-over').forEach(c=>c.classList.remove('drag-over'));
      });
      crmEl.addEventListener('dragover', e=>{
        const col = e.target.closest('[data-kanban-stage]');
        if(!col) return;
        e.preventDefault();
        col.classList.add('drag-over');
      });
      crmEl.addEventListener('dragleave', e=>{
        const col = e.target.closest('[data-kanban-stage]');
        if(col && !col.contains(e.relatedTarget)) col.classList.remove('drag-over');
      });
      crmEl.addEventListener('drop', e=>{
        const col = e.target.closest('[data-kanban-stage]');
        if(!col) return;
        e.preventDefault();
        crmEl.querySelectorAll('.kanban-col.drag-over').forEach(c=>c.classList.remove('drag-over'));
        const idx = Number(e.dataTransfer.getData('text/plain'));
        if(!Number.isFinite(idx) || !acoes[idx]) return;
        const destino = col.dataset.kanbanStage;
        const origem = kanbanStageTicket(acoes[idx]);
        if(destino === origem) return;
        abrirModalEvoluirTicket(idx, kanbanTipoEvolucaoPorDestino(destino));
      });
    }
  }

  function abrirModalEditarAcao(idx){
    normalizarTicketsCRM();
    const a = acoes[idx];
    if(!a || acaoExcluida(a)) return;
    $('modalContent').innerHTML = `<p class="eyebrow">CRM Cobrança</p>
      <h2>Editar ${htm(ticketLabel(a))}</h2>
      <p>Altere apenas as informações digitadas erradas. O número do ticket será preservado.</p>
      <form id="formEditarAcao" class="action-form">
        ${responsavelSelectHtml('edit', a.responsavel || 'Usuário')}
        <label class="form-field"><span>Tipo de ação *</span><select id="editTipo" required>${opcoesHtml(CRM_TIPOS_ACAO, a.tipo)}</select></label>
        <label class="form-field"><span>Data do contato *</span><input id="editData" type="date" value="${htm(a.data||'')}" required /></label>
        <label class="form-field"><span>Hora</span><input id="editHora" type="time" value="${htm(a.hora||'')}" /></label>
        <label class="form-field"><span>Resultado *</span><select id="editResultado" required>${opcoesHtml(CRM_RESULTADOS, a.resultado)}</select></label>
        <label class="form-field"><span>Estágio *</span><select id="editEstagio" required>${opcoesHtml(CRM_ESTAGIOS_FLUXO, a.statusNegociacao)}</select></label>
        <div id="editPromessaSection" class="promise-fields" style="display:none">
          <div class="form-section-title">Promessa de pagamento</div>
          <label class="form-field"><span>Valor prometido</span><input id="editPromessaValor" type="number" min="0" step="0.01" value="${Number(a.promessaValor)||''}" /></label>
          <label class="form-field"><span>Data prometida</span><input id="editPromessaData" type="date" value="${htm(a.dataPromessa||'')}" /></label>
          <label class="form-field"><span>Status da promessa</span><select id="editPromessaStatus"><option value="">Sem promessa</option>${['Aguardando','Vencida','Cumprida'].map(v=>`<option ${a.statusPromessa===v?'selected':''}>${v}</option>`).join('')}</select></label>
        </div>
        <div class="form-section-title">Próxima ação</div>
        <label class="form-field"><span>Próxima ação *</span><select id="editProxima" required>${opcoesHtml(CRM_PROXIMAS_ACOES, a.proximaAcao)}</select></label>
        <label class="form-field"><span>Data da próxima ação *</span><input id="editProximaData" type="date" value="${htm(a.proximaData||'')}" required /></label>
        <label class="form-field"><span>Hora da próxima ação *</span><input id="editProximaHora" type="time" value="${htm(a.proximaHora||'')}" required /></label>
        <label class="form-field full"><span>Observação *</span><textarea id="editObs" rows="4" required>${htm(a.obs||'')}</textarea></label>
        <div id="editErro" class="form-error" role="alert"></div>
        <div class="modal-actions-row"><button type="submit">Salvar alterações</button><button type="button" class="secondary" id="btnCancelarEditAcao">Cancelar</button></div>
      </form>`;
    $('modal').classList.add('open');
    configurarResponsavelSelect('edit');
    function atualizarSecaoPromessaEdit(){
      const est = $('editEstagio'); const box = $('editPromessaSection');
      if(!est || !box) return;
      const estagioNorm = norm(est.value || '');
      const promessaObrigatoria = estagioNorm === 'promessa';
      const mostrar = promessaObrigatoria || estagioNorm === 'negociacao';
      box.style.display = mostrar ? '' : 'none';
      if($('editPromessaValor')) $('editPromessaValor').required = promessaObrigatoria;
      if($('editPromessaData')) $('editPromessaData').required = promessaObrigatoria;
      if($('editPromessaStatus') && mostrar && !$('editPromessaStatus').value) $('editPromessaStatus').value = promessaObrigatoria ? 'Aguardando' : '';
      if(!mostrar){
        if($('editPromessaValor')) $('editPromessaValor').value = '';
        if($('editPromessaData')) $('editPromessaData').value = '';
        if($('editPromessaStatus')) $('editPromessaStatus').value = '';
      }
    }
    if($('editEstagio')) $('editEstagio').addEventListener('change', atualizarSecaoPromessaEdit);
    atualizarSecaoPromessaEdit();
    $('btnCancelarEditAcao').onclick = ()=>$('modal').classList.remove('open');
    $('formEditarAcao').onsubmit = async e=>{
      e.preventDefault();
      const obs = String($('editObs').value||'').trim();
      if(!validarResponsavelSelect('edit','editErro')) return;
      if(!obs){ $('editErro').textContent = 'Informe a observação.'; return; }
      if(!$('editProximaData').value || !$('editProximaHora').value){ $('editErro').textContent = 'Informe a próxima ação com data e hora.'; return; }
      const editEstagioNorm = norm($('editEstagio').value || '');
      const editPromessaObrigatoria = editEstagioNorm === 'promessa';
      const editPromessaPermitida = editPromessaObrigatoria || editEstagioNorm === 'negociacao';
      if(editPromessaObrigatoria && !num($('editPromessaValor').value)){ $('editErro').textContent = 'Informe o valor da promessa de pagamento.'; return; }
      if(editPromessaObrigatoria && !$('editPromessaData').value){ $('editErro').textContent = 'Informe a data prometida da promessa de pagamento.'; return; }
      Object.assign(a, {
        responsavel: obterResponsavelSelect('edit') || 'Usuário',
        tipo: $('editTipo').value,
        data: $('editData').value,
        hora: $('editHora').value,
        resultado: $('editResultado').value,
        statusNegociacao: $('editEstagio').value,
        promessaValor: editPromessaPermitida ? (num($('editPromessaValor').value) || 0) : 0,
        dataPromessa: editPromessaPermitida ? $('editPromessaData').value : '',
        statusPromessa: editPromessaPermitida ? ($('editPromessaStatus').value || (editPromessaObrigatoria ? 'Aguardando' : '')) : '',
        proximaAcao: $('editProxima').value,
        proximaData: $('editProximaData').value,
        proximaHora: $('editProximaHora').value,
        obs: obs,
        editadoEm: new Date().toLocaleString('pt-BR'),
        editadoPor: usuarioAtualEmail()
      });
      try{ await salvarAcaoNuvem(a); }catch(err){ console.error('Erro ao editar ticket na nuvem:', err); $('editErro').textContent = 'Erro ao salvar na nuvem: ' + (err && (err.code || err.message) ? (err.code || err.message) : 'tente novamente.'); return; }
      $('modal').classList.remove('open');
      render();
    };
  }

  async function excluirAcaoCRM(idx){
    normalizarTicketsCRM();
    const a = acoes[idx];
    if(!a || acaoExcluida(a)) return;
    const motivo = prompt(`Informe o motivo para excluir o ${ticketLabel(a)}. O registro não será apagado; ficará marcado como excluído na linha do tempo.`);
    if(motivo === null) return;
    const motivoLimpo = String(motivo||'').trim();
    if(!motivoLimpo){ alert('Informe um motivo para registrar a exclusão.'); return; }
    a.excluida = true;
    a.excluidoEm = new Date().toLocaleString('pt-BR');
    a.motivoExclusao = motivoLimpo;
    a.statusAcao = 'Excluída';
    a.statusNegociacaoAntesExclusao = a.statusNegociacao || '';
    a.statusNegociacao = 'Excluída';
    a.excluidoPor = usuarioAtualEmail();
    try{ await salvarAcaoNuvem(a); }catch(err){ console.error('Erro ao excluir ticket na nuvem:', err); alert('Não foi possível registrar a exclusão na nuvem. Tente novamente.'); return; }
    render();
  }

  function abrirDetalhe(key){
    const c = agrupar().find(x=>(x.codcli||x.cliente)===key);
    if(!c) return;
    const historico = [...c.duplicatas].sort((a,b)=>{
      const dias = (Number(b.dias)||0) - (Number(a.dias)||0);
      if(dias !== 0) return dias;
      return (Number(b.valor)||0) - (Number(a.valor)||0);
    });
    $('modalContent').innerHTML = `<p class="eyebrow">Histórico do cliente</p><h2>${c.cliente}</h2>
      <div class="detail-grid">
        <div class="detail-card"><small>Código</small><strong>${c.codcli||'-'}</strong></div>
        <div class="detail-card"><small>Representante</small><strong>${c.representante||'-'}</strong></div>
        <div class="detail-card"><small>Total vencido</small><strong>${money(c.total)}</strong></div>
        <div class="detail-card"><small>Maior atraso</small><strong>${c.maiorAtraso} dias</strong></div>
        <div class="detail-card"><small>Score</small><strong><span class="score ${scoreClass(c.score)}">${scoreIcon(c.score)} ${c.score}</span></strong></div>
      </div>
      <p><strong>Cidade:</strong> ${c.cidade||'-'} &nbsp; <strong>Telefone:</strong> ${telefoneCompleto(c)||'-'}</p>
      <div class="duplicatas"><h3>Duplicatas em aberto</h3><div class="modal-history-scroll"><table><thead><tr><th>Duplicata</th><th>Fatura</th><th>Pedido</th><th>Emissão</th><th>Vencimento</th><th>Valor</th><th>Dias atraso</th><th>Status</th></tr></thead><tbody>
      ${historico.map(d=>`<tr><td>${d.duplicata||'-'}</td><td>${d.fatura||'-'}</td><td>${d.pedido||'-'}</td><td>${d.emissao||'-'}</td><td>${d.vencimento||'-'}</td><td><strong>${money(d.valor)}</strong></td><td><strong>${Number.isFinite(Number(d.dias)) ? Number(d.dias) : 0} dias</strong></td><td>${d.status||'-'}</td></tr>`).join('')}
      </tbody></table></div></div>
      <h3>Leitura automática</h3><p>${c.score==='Não vender'?'Cliente deve ser bloqueado para novas vendas até negociação formal.':c.score==='Atenção'?'Cliente merece acompanhamento antes de liberar novo crédito.':'Cliente com risco controlado no momento.'}</p>`;
    $('modal').classList.add('open');
  }

  function splitCsvLine(line, sep){
    const out=[]; let cur='', q=false;
    for(let i=0;i<line.length;i++){ const ch=line[i]; if(ch==='"'){ if(q&&line[i+1]==='"'){cur+='"';i++;} else q=!q; } else if(ch===sep&&!q){out.push(cur.trim());cur='';} else cur+=ch; }
    out.push(cur.trim()); return out;
  }
  function detectSep(text){ const first=text.split(/\r?\n/).find(l=>l.trim())||''; return [';',',','\t'].sort((a,b)=>(first.split(b).length-first.split(a).length))[0]; }
  const aliases = {
    codcli:['codcli','codigo','cod_cliente','cliente_codigo'], cliente:['cliente','nome','razao','razao_social','nome_cliente'], fantasia:['fantasia','nome_fantasia'], duplicata:['duplicata','num_duplicata','numero_duplicata','nr_duplicata','titulo','numero_titulo'], representante:['representante','rep','codrep','vendedor'], cidade:['cidade','municipio'], telefone:['telefone','fone','celular','tel'], pedido:['pedido','num_pedido','numero_pedido','nr_pedido','ped'], fatura:['fatura','num_fatura','numero_fatura','nf','nota'], valor:['valor','valor2','vlr','saldo','valor_divida'], vencimento:['vencimento','dt_vencto','dt_vencimento','vencto','dt vencto','dt vencimento','data_vencimento'], emissao:['emissao','dt_emissao','dt,emissao','data_emissao','dataemissao','dt emissao','data emissão','dt_emissão'], status:['status','situacao'], dias:['dias','dias_atraso','diasatraso','atraso']
  };
  function normalizarHeader(h){
    return norm(h).replace(/[\s\-]+/g,'_').replace(/_+/g,'_');
  }

  function normalizarRegistroERP(registro){
    registro.codcli = limparValorCsv(registro.codcli);
    registro.cliente = limparValorCsv(registro.cliente);
    registro.duplicata = limparValorCsv(registro.duplicata);
    registro.fatura = limparValorCsv(registro.fatura);
    registro.emissao = limparValorCsv(registro.emissao);
    registro.vencimento = limparValorCsv(registro.vencimento);
    registro.representante = limparValorCsv(registro.representante);
    registro.cidade = limparValorCsv(registro.cidade);
    registro.telefone = limparValorCsv(registro.telefone);
    registro.pedido = limparValorCsv(registro.pedido);
    registro.status = limparValorCsv(registro.status || 'Aberta');
    registro.valor = num(registro.valor);
    const diasInformado = registro.dias;
    const diasNumero = Number(diasInformado);
    registro.dias = daysLate(registro.vencimento);
    Object.keys(registro).forEach(k=>{ if(registro[k] === undefined) delete registro[k]; });
    return registro;
  }

  function montarRegistroPorMapa(cols, map){
    return normalizarRegistroERP({
      codcli: cols[map.codcli] ?? '',
      cliente: cols[map.cliente] ?? '',
      fantasia: cols[map.fantasia] ?? '',
      duplicata: cols[map.duplicata] ?? '',
      fatura: cols[map.fatura] ?? '',
      emissao: cols[map.emissao] ?? '',
      vencimento: cols[map.vencimento] ?? '',
      valor: cols[map.valor] ?? '',
      representante: cols[map.representante] ?? '',
      cidade: cols[map.cidade] ?? '',
      telefone: cols[map.telefone] ?? '',
      pedido: cols[map.pedido] ?? '',
      status: cols[map.status] ?? 'Aberta',
      dias: map.dias !== undefined ? num(cols[map.dias]) : undefined
    });
  }

  function montarRegistroLayoutERP(cols){
    // Layout oficial informado:
    // CODCLI, CLIENTE, DUPLICATA, DT_EMISSAO, DT_VENCTO, VALOR, REPRESENTANTE, CIDADE, TELEFONE, FATURA, PEDIDO, STATUS
    return normalizarRegistroERP({
      codcli: cols[0] ?? '',
      cliente: cols[1] ?? '',
      duplicata: cols[2] ?? '',
      emissao: cols[3] ?? '',
      vencimento: cols[4] ?? '',
      valor: cols[5] ?? '',
      representante: cols[6] ?? '',
      cidade: cols[7] ?? '',
      telefone: cols[8] ?? '',
      fatura: cols[9] ?? '',
      pedido: cols[10] ?? '',
      status: cols[11] ?? 'Aberta'
    });
  }

  function analisarImportacaoCsv(text, fileName){
    const assinaturaArquivo = hashTexto(text);
    const sep = detectSep(text);
    const linhas = text.split(/\r\n|\n|\r/).filter(l=>l.trim()).map(l=>splitCsvLine(l,sep).map(limparValorCsv));
    const resultado = {
      assinaturaArquivo,
      fileName: fileName || '',
      sep,
      linhasTotal: 0,
      hasHeader: false,
      usarLayoutERP: true,
      linhas: [],
      novos: [],
      duplicados: [],
      ignorados: [],
      amostra: []
    };

    if(!linhas.length) return resultado;

    const header = linhas[0].map(normalizarHeader);
    const todosAliases = Object.values(aliases).flat().map(normalizarHeader);
    const hasHeader = header.some(h=>todosAliases.includes(h));
    const data = hasHeader ? linhas.slice(1) : linhas;
    const map = {};

    if(hasHeader){
      Object.entries(aliases).forEach(([campo,als])=>{
        const aliasesNorm = als.map(normalizarHeader);
        const idx = header.findIndex(h=>aliasesNorm.includes(h));
        if(idx>=0) map[campo]=idx;
      });
    }

    const headerOficialERP = header.slice(0,12).join('|') === ['codcli','cliente','duplicata','dt_emissao','dt_vencto','valor','representante','cidade','telefone','fatura','pedido','status'].join('|');
    const usarLayoutERP = headerOficialERP || !hasHeader || map.cliente === undefined || map.valor === undefined || map.duplicata === undefined;

    resultado.hasHeader = hasHeader;
    resultado.usarLayoutERP = usarLayoutERP;
    resultado.linhasTotal = data.length;

    const existentesLocal = new Set(registros.map(idRegistro));
    const existentesCloud = new Set(cloudRegistrosIds);
    const vistosNoArquivo = new Set();

    data.forEach((cols, idx)=>{
      const numeroLinha = idx + (hasHeader ? 2 : 1);
      const registro = usarLayoutERP ? montarRegistroLayoutERP(cols) : montarRegistroPorMapa(cols, map);
      const linha = { numeroLinha, registro, status: 'novo', motivo: '', id: '', idCloud: '' };

      if(!registro.cliente || !registro.valor){
        linha.status = 'ignorado';
        linha.motivo = !registro.cliente ? 'Cliente ausente' : 'Valor ausente/zerado';
        resultado.ignorados.push(linha);
        resultado.linhas.push(linha);
        return;
      }

      const id = idRegistro(registro);
      const idCloud = docIdRegistro(registro);
      linha.id = id;
      linha.idCloud = idCloud;

      if(existentesLocal.has(id) || existentesCloud.has(idCloud)){
        linha.status = 'duplicado';
        linha.motivo = 'Já existe no sistema';
        resultado.duplicados.push(linha);
      } else if(vistosNoArquivo.has(id)){
        linha.status = 'duplicado';
        linha.motivo = 'Duplicado dentro do próprio arquivo';
        resultado.duplicados.push(linha);
      } else {
        vistosNoArquivo.add(id);
        resultado.novos.push(registro);
        if(resultado.amostra.length < 5) resultado.amostra.push(registro);
      }

      resultado.linhas.push(linha);
    });

    return resultado;
  }

  function importPreviewStatusLabel(status){
    if(status === 'duplicado') return 'Duplicado';
    if(status === 'ignorado') return 'Ignorado';
    return 'Novo';
  }

