  $('btnCarregarDemo').onclick = ()=>{ registros = [...demo]; arquivosImportados=[]; clienteSelecionadoKey=null; render(); };
  $('btnLimparTudo').onclick = async ()=>{
    const msg = cloudAtivo
      ? 'Limpar clientes, duplicatas e histórico de importações da NUVEM? Isso atualizará todos os usuários logados. Os tickets/CRM serão preservados.'
      : 'Limpar todos os dados locais desta demonstração?';
    if(!confirm(msg)) return;

    if(cloudAtivo){
      try{
        $('importStatus').textContent = 'Limpando dados da nuvem... aguarde.';
        await limparDadosNuvem();
      }catch(err){
        console.error('Erro ao limpar Firestore:', err);
        alert('Não foi possível limpar os dados da nuvem: ' + (err.message || err));
        return;
      }
    }

    registros=[]; arquivosImportados=[]; clienteSelecionadoKey=null;
    localStorage.setItem(LS, JSON.stringify({registros,acoes,arquivosImportados,clientesCadastro}));
    render();
    $('importStatus').textContent = cloudAtivo ? 'Dados de clientes/duplicatas limpos na nuvem.' : 'Dados locais limpos.';
  };

